INSERT INTO incidents (id, name, risk_coverage_vendors, incident_handler_vendors, total_vendors) VALUES
  (1, 'Railway suffers 8-hour platform outage after GCP erroneous account suspension', 4, 1, 5),
  (2, 'SpaceX contractor worker dies in scaffolding fall at Starbase; OSHA investigates', 3, 2, 5),
  (3, 'California Dairies Salmonella recall cascade expands to dozens of downstream food products', 4, 2, 6),
  (4, 'GitHub internal repositories breached via TanStack supply chain cascade', 3, 2, 5),
  (5, 'NYC Health + Hospitals discloses 1.8M-person breach including biometric data', 5, 1, 6),
  (6, 'Saks Global Chapter 11 leaves hundreds of fashion vendors unpaid', 3, 2, 5),
  (7, 'UP Fintech Tiger Brokers fined RMB 308 million by CSRC Beijing Bureau for unlicensed operations', 3, 3, 6),
  (8, 'Microsoft Exchange Server OWA zero-day CVE-2026-42897 actively exploited, no patch', 6, 2, 8),
  (9, 'Rosneft Tuapse refinery cleanup declared complete amid disputed Black Sea oil spill', 4, 3, 7),
  (10, 'Starbucks Korea ''Tank Day'' blunder triggers national boycott and CEO firing', 1, 1, 2);
