INSERT INTO products (id, vendor_id, incident_id, name, what_they_do, product_url, vendor_group, role, primary_mc, covers_controls, ai_verdict, confidence, fit, how_it_mitigates, known_limits, score_rationale) VALUES
  (1, 1, 1, 'Datadog External Provider Status', 'Datadog is an observability and security platform that provides real-time monitoring of cloud infrastructure and third-party providers. Its External Provider Status feature detects third-party cloud provider degradations before they are confirmed by vendor status pages, using aggregated APM telemetry across thousands of customers.', 'https://www.datadoghq.com/blog/external-provider-status/', 'Risk Coverage', 'enabler', 'MC-TEC-003', '{"MC-TEC-003"}', 52, 'DIRECTIONAL', 'partial', 'Datadog External Provider Status operates entirely independently of the monitored infrastructure — it uses Datadog''s own globally distributed APM data pipeline to detect degradations by observing aggregated error rates across thousands of customer environments. When GCP exhibits anomalous error patterns consistent with a service suspension, Datadog''s Bayesian detection model surfaces the degradation before the provider confirms it. The customer can configure a Datadog monitor to page the on-call SRE within seconds of a detected degradation, satisfying the 60-second alerting requirement in MC-TEC-003. Crucially, since Datadog''s own infrastructure is independent of GCP, this monitoring path survives a total GCP account suspension — the very failure mode that affected Railway on May 19, 2026.', 'Datadog External Provider Status does not document specific monitoring of GCP account-suspension enforcement events as a named provider signal. Coverage for GCP is not explicitly listed alongside the 13 named AWS services.', 'Datadog''s External Provider Status addresses third-party degradation detection (adjacent coverage) but the Railway incident was an account suspension — an enforcement/policy action, not a service degradation — making the vendor''s core capability only tangentially relevant to the actual failure mode, with evidence drawn from product pages rather than named customer case studies.'),
  (2, 2, 1, 'IBM NS1 Connect – Intelligent DNS Traffic Steering with Filter Chain Failover', 'IBM NS1 Connect transforms DNS into a real-time traffic control plane that automatically reroutes traffic between infrastructure providers using health-check-driven filter chains, enabling active-active and active-passive multi-cloud failover independent of any single cloud provider.', 'https://www.ibm.com/new/product-blog/how-to-improve-network-resilience-with-ns1-connect-filter-chains', 'Risk Coverage', 'enabler', 'MC-TEC-001', '{"MC-TEC-001","MC-TEC-012","MC-TPR-022"}', 67, 'INFERRED', 'full', 'IBM NS1 Connect operates as a DNS-layer traffic control plane completely independent of any single cloud provider. For Railway''s use case, NS1 would be configured with an active-passive filter chain where GCP endpoints are designated as primary and Railway Metal and AWS are designated as passive failover endpoints. NS1''s health monitoring continuously checks the availability of the GCP-hosted API endpoint. When GCP''s endpoint becomes unreachable — as it did on May 19, 2026 — the filter chain''s ''Up'' filter immediately detects the failure and the ''Priority'' filter automatically redirects all DNS queries to Railway Metal or AWS endpoints, routing traffic away from GCP before TTL expiry can cause a global 404 cascade. This automated DNS-level failover directly prevents the routing-cache expiry cascade that blacked out all Railway regions.', 'IBM NS1 Connect provides DNS-level failover but does not address the CloudSQL database replication requirement of MC-TEC-016; database failover to a non-GCP replica must be handled separately.', 'NS1 Connect''s DNS-layer traffic rerouting and active-passive failover capabilities map precisely to the multi-cloud provider independence required by this incident, but scores are tempered by evidence resting entirely on product-page marketing claims with no named customer case studies, and IBM''s brand weight introduces meaningful reputation-halo risk relative to the capability-led evidence base.'),
  (3, 3, 1, 'Gremlin Chaos Engineering Platform – Blackhole Attack and Disaster Recovery FireDrills', 'Gremlin is an enterprise chaos engineering platform that enables teams to simulate real-world infrastructure failures — including network blackhole attacks that drop all traffic to specific cloud provider endpoints — to validate disaster recovery plans and business continuity procedures in a safe, controlled, and reversible way.', 'https://www.gremlin.com/blog/getting-started-with-blackhole-attacks', 'Risk Coverage', 'enabler', 'MC-OPS-008', '{"MC-OPS-008","MC-OPS-002"}', 68, 'INFERRED', 'full', 'Gremlin''s Blackhole attack targeted at GCP hostnames (e.g., sqladmin.googleapis.com and the Railway production API''s GCP endpoint) will drop all network traffic between Railway Metal and AWS nodes and GCP, simulating the exact failure mode that occurred on May 19, 2026. This validates whether the hardened routing-table TTL (MC-TEC-017), the non-GCP control-plane seeding (MC-TEC-001), and the non-GCP CloudSQL read replica (MC-TEC-016) together prevent global 404 propagation without GCP reinstatement. Gremlin''s Scenarios feature allows the team to stage the attack with an increasing blast radius (first one hub, then all regions), and the built-in fail-safe halts the attack if the Gremlin agent loses connectivity, providing a safety net for a production-grade FireDrill.', NULL, 'Gremlin''s verified capabilities map closely to third-party cloud provider outage simulation (exactly the Railway scenario type) and the claimed MCs align with chaos-engineering-based DR validation, but evidence rests on product documentation and marketing copy rather than named customer case studies, and the incident''s root cause (erroneous account suspension) is an administrative/policy failure that Gremlin''s network-layer blackhole simulation approximates but does not precisely replicate.'),
  (4, 4, 1, 'Atlassian Statuspage', 'Atlassian Statuspage is a hosted incident communication tool that enables companies to inform users about outages and scheduled maintenance via a publicly accessible status page, with subscriber notifications sent by Atlassian''s own infrastructure independent of the company''s own systems.', 'https://support.atlassian.com/statuspage/docs/what-is-statuspage/', 'Risk Coverage', 'enabler', 'MC-OPS-018', '{"MC-OPS-018","MC-REP-005"}', 72, 'INFERRED', 'full', 'Atlassian Statuspage is hosted on Atlassian''s own globally distributed infrastructure, not on Railway''s GCP-hosted systems. When GCP suspends Railway''s account and takes the API, CloudSQL, and GCP-hosted compute offline simultaneously, Statuspage continues to serve Railway''s status page and deliver email and SMS notifications to subscribers via Atlassian''s own notification infrastructure. An on-call SRE can update Railway''s Statuspage from any internet-connected device (including a personal device not depending on GCP), publishing an initial incident notice within minutes of detecting the outage. This directly satisfies MC-OPS-018''s 2-hour customer-communication requirement even when GCP-dependent communication channels are unavailable.', 'Atlassian Statuspage does not perform automated incident detection; an on-call SRE or an integrated external monitoring tool must trigger the incident publication. If all Railway communication channels depend on GCP, there is a risk of delay in creating the first Statuspage incident notice.', 'Statuspage directly addresses the MC-OPS-018/MC-REP-005 communication controls with a verified, infrastructure-independent notification capability purpose-built for exactly this type of platform-wide outage scenario, but evidence rests on product-page claims rather than named customer case studies, and Atlassian''s brand recognition introduces a mild reputation-halo factor.'),
  (5, 3, 1, 'Gremlin Chaos Engineering Platform – Disaster Recovery Validation', 'Gremlin provides a chaos engineering platform used after incidents to validate post-incident architectural changes by reproducing the failure mode in a controlled environment, confirming that the remediations eliminate the original single point of failure before returning to production confidence.', 'https://www.gremlin.com/community/tutorials/testing-disaster-recovery-with-chaos-engineering', 'Incident Handler', 'implementor', NULL, '{}', 67, 'INFERRED', 'full', 'After Railway implements the post-incident architectural remediations (TTL hardening, non-GCP routing seeding, CloudSQL replica), Gremlin is used to validate that these changes actually prevent a repeat of the May 19, 2026 all-regions blackout. A Gremlin Scenario targets all GCP endpoints used by Railway''s API and CloudSQL with a Blackhole attack, simulating the account suspension. If the revised routing architecture is sound, Railway Metal and AWS nodes continue to serve traffic via independently seeded routing tables for the duration of the blackhole. The Scenario also adds a GitHub rate-limiting stressor as a secondary stage to replicate the compound failure. Gremlin automatically halts the attack if the Gremlin agent loses connectivity, providing a fail-safe for production-grade testing.', 'Gremlin does not provide legal advisory, contract renegotiation with GCP, or employment law compliance services; its scope is limited to resilience testing and DR plan validation.', 'Gremlin''s Blackhole network attack capability maps directly to the post-incident validation use case (simulating cloud provider endpoint unavailability), and both verified claims confirm this specific mechanism, but evidence rests on product-page-level documentation rather than named customer case studies, and the role is post-incident validation rather than active incident handling, creating a slight adjacency gap on D1 and D3.'),
  (6, 5, 2, 'SafetyCulture – OSHA Scaffold Inspection Checklist / Construction Safety Platform', 'SafetyCulture (formerly iAuditor) is a mobile-first operations and safety platform that provides digital checklists, inspection workflows, real-time hazard reporting, and training delivery tools for construction and industrial worksites, including purpose-built OSHA-compliant scaffold inspection templates.', 'https://safetyculture.com/library/construction/osha-scaffold-inspection-checklist', 'Risk Coverage', 'enabler', 'MC-PPL-008', '{"MC-PPL-008","MC-PHY-009","MC-PHY-010"}', 72, 'INFERRED', 'partial', 'SafetyCulture provides a pre-configured OSHA Scaffold Inspection Checklist that digitises the shift-by-shift inspection regime required by 29 CFR 1926.451(f)(3). Inspectors use the mobile platform to check guardrails, mid-rails, personal fall arrest systems, footings, baseplates, braces, and planking against OSHA-compliant criteria, capturing photos and inspector signatures in a tamper-evident digital log. For MC-PHY-009, the platform preserves a per-scaffold evidentiary record (photos, inspection findings, signatures) that can be retained for OSHA Region VI on request. For MC-PHY-010, SafetyCulture supports a scaffolding stand-down by enabling mass checklist deployment to all active scaffolds simultaneously, with return-to-service sign-offs tracked per scaffold. For MC-PPL-008, the platform''s pre-shift inspection workflow ensures no scaffold is returned to service after the 15 May 2026 fatality without a documented competent-person review. The client must separately designate the named competent person.', NULL, 'SafetyCulture maps precisely to the scaffold inspection and fall protection controls at issue (D1/D3 high) but evidence rests on product-page and template claims rather than named customer case studies or independent validation, and its strong brand recognition introduces a moderate reputation-halo factor that limits the independence score.'),
  (7, 6, 2, 'Cority Contractor Management Software', 'Cority provides a construction EHS+ platform with a dedicated contractor management module that manages the full contractor lifecycle — from pre-qualification to ongoing monitoring and post-job review — including training verification, competent-person qualification tracking, and permit-to-work integration.', 'https://www.cority.com/safety-cloud/contractor-management-software/', 'Risk Coverage', 'enabler', 'MC-PPL-020', '{"MC-PPL-019","MC-PPL-020","MC-TPR-021","MC-TPR-022"}', 68, 'INFERRED', 'partial', 'Cority''s Contractor Management module addresses the core preventive requirements arising from the Bautista fatality. For MC-PPL-020, the platform''s pre-qualification workflow can be configured to require all Starbase scaffold contractors to disclose OSHA injury-rate history and citation records as a gate to site access. For MC-PPL-019 and MC-TPR-021, Cority tracks training records and competent-person designations at the individual worker level, enabling SpaceX to verify that each scaffold-erector holds current OSHA 29 CFR 1926.454(a) training before any elevated work begins. For MC-TPR-022, the permit-to-work module enforces approval workflows before high-risk tasks commence, embedding a de facto stop-work authority gate. Cority''s AI-powered risk scoring identifies contractor risk patterns early, supporting proactive exclusion of high-risk contractors from site access.', NULL, 'Cority''s dedicated construction EHS contractor management module aligns closely with the MCs (pre-qualification, training verification, permit-to-work, competent-person tracking) and the scaffolding-fall scenario''s root causes, but all verified claims derive from marketing/product-page copy with no named customer case studies or third-party certifications, capping evidence strength and keeping the score in the inferred tier.'),
  (8, 7, 2, 'ISNetworld – Contractor Prequalification & Ongoing Monitoring', 'ISN is the global leader in contractor and supplier information management, operating ISNetworld — a platform that enables hiring clients to collect, verify, trend, and audit contractors'' health and safety programs, OSHA injury statistics, training records, and insurance documentation as a condition of site access.', 'https://www.isnetworld.com/en', 'Risk Coverage', 'enabler', 'MC-PPL-020', '{"MC-PPL-020","MC-TPR-021"}', 62, 'INFERRED', 'partial', 'ISNetworld addresses the MC-PPL-020 requirement to extend SpaceX''s contractor pre-qualification standard by providing a structured digital registry where all Starbase scaffold and temporary-works contractors must submit their OSHA injury-rate history (TRIR, DART), open or contested citations, and written health and safety programs as a condition of receiving a qualified status and site access. Hiring clients can set custom thresholds — e.g., suspending access for contractors with TRIR above a defined rate or with open fatality-related citations. For MC-TPR-021, ISNetworld''s worker-level training module enables SpaceX to assign and track OSHA 29 CFR 1926.454(a) scaffolding training records at the individual worker level, providing documentary evidence that each scaffold worker is qualified before they access any Starbase scaffold.', 'ISNetworld does not conduct physical site audits, designate competent persons, or produce the legal documentation for contractual stop-work authority provisions — those require SpaceX''s legal and EHS functions acting independently.', 'ISN''s core product directly addresses third-party contractor safety prequalification and OSHA recordkeeping (MC-PPL-020, MC-TPR-021), giving solid coverage specificity for this scaffolding fatality scenario, but evidence is limited to product-page claims with no named customer case studies, and ISN''s dominant market position introduces meaningful reputation-halo risk that tempers the independence score.'),
  (9, 8, 2, 'Workplace Safety and Catastrophe Management Practice Group', 'Fisher Phillips'' Workplace Safety and Catastrophe Management Practice Group provides OSHA defense counsel, catastrophe response, OSHA investigation representation, and safety compliance advisory for employers across all industries including construction, with a documented practice of responding immediately following workplace fatalities and defending willful, egregious, and repeat OSHA citations.', 'https://www.fisherphillips.com/en/capabilities/services/workplace-safety-and-catastrophe-management', 'Incident Handler', 'implementor', NULL, '{}', 82, 'INFERRED', 'full', 'Following the 18 May 2026 OSHA Region VI investigation confirmation, Fisher Phillips'' Workplace Safety and Catastrophe Management team would be engaged to: (1) immediately conduct a privilege-protected post-accident investigation before OSHA arrives for an on-site inspection, documenting the scaffold''s state, PFAS records, and competent-person designation status (MC-REG-004, MC-PHY-009); (2) respond to OSHA Region VI''s information requests and manage the inspection posture to avoid escalation to willful classification, drawing on the firm''s documented repeat and willful citation defence experience (MC-REG-008, MC-REG-014); (3) conduct a strategic reassessment of whether to continue contesting the January 2026 $115,850 citation package in light of the new fatality (MC-REG-014); (4) manage catastrophe communications including media, family communications, and government stakeholder briefings (MC-REP-016); and (5) conduct a site safety audit to identify and document corrective actions across all active Starbase scaffolds before OSHA''s on-site inspection.', NULL, 'Fisher Phillips scores very high on coverage and incident specificity because their verified capabilities map precisely onto the active OSHA Region VI fatality investigation scenario — immediate post-accident investigation under privilege, catastrophe management, media and family communications, and repeat/willful citation defense — but evidence strength is capped at the product-page/marketing-copy tier with no named client case studies verified, and the confidence level is INFERRED rather than DOCUMENTED for that reason.'),
  (10, 9, 2, 'Workplace Safety and Health Practice Group', 'Ogletree Deakins has more than 65 attorneys devoted to workplace safety law and is one of only two law firms ranked Band 1 in Occupational Safety and Health by Chambers USA, providing OSHA investigation response, willful and egregious citation defence, Severe Violator Enforcement Program representation, and immediate workplace accident investigation across all industries including construction.', 'https://ogletree.com/practices-industries/workplace-safety-and-health/', 'Incident Handler', 'implementor', NULL, '{}', 91, 'DOCUMENTED', 'full', 'Following the 18 May 2026 OSHA Region VI investigation confirmation, Ogletree Deakins would be engaged to: (1) immediately respond to the Starbase fatality, direct the privilege-protected investigation, and communicate SpaceX''s defences to OSHA Region VI early in the inspection process — as they successfully did in the Puerto Rico fatality case — to prevent citation issuance or minimise penalty exposure (MC-REG-004); (2) assess the risk of repeat or willful classification given Starbase''s 17-citation history and provide strategic advice on whether to continue contesting the January 2026 $115,850 citation package (MC-REG-014); (3) represent SpaceX before OSHA Region VI and, if necessary, the Occupational Safety and Health Review Commission in defence of any new citations arising from the Bautista fatality (MC-REG-008); and (4) assess 29 CFR 1904.39 reporting obligations and advise on the voluntary late-notification strategy if the eight-hour window was missed (MC-REG-016).', 'Ogletree Deakins is a law firm and does not provide physical EHS field services, scaffold inspections, or specialist public affairs outreach to government programme offices.', 'Ogletree Deakins scores near-maximum because all four verified capability claims directly map to the Bautista fatality scenario — immediate accident response, OSHA Region VI investigation defense, construction fall-protection citation vacatur, and a prior fatality resulting in no citations — with the only deductions reflecting the absence of a named SpaceX-tier client reference and a modest reputation halo given their Band 1 Chambers ranking.'),
  (11, 10, 3, 'SafetyChain Food Safety Programs – Environmental Monitoring and CAPA', 'SafetyChain is a digital plant management platform for food and beverage manufacturers that digitises food safety programmes including Pre-Op hygiene, HACCP monitoring, sanitation checks, and environmental monitoring with built-in CAPA workflows and exception-based oversight.', 'https://safetychain.com/platform/food-safety-programs', 'Risk Coverage', 'enabler', 'MC-OPS-005', '{"MC-OPS-005","MC-OPS-025"}', 72, 'INFERRED', 'enabling', 'SafetyChain digitises the environmental monitoring programme by replacing paper-based sanitation and microbiological checks with digital workflows that automatically trigger CAPA when a corrective-action threshold is breached. When a Salmonella-positive zone-2 swab result is entered, the platform immediately surfaces the exception, assigns a CAPA task with deadline to the sanitation or QA team, links the CAPA to the originating check record, and requires documented closure before the issue is marked resolved. For MC-OPS-025, the CAPA module enforces a root-cause documentation step before a CAPA can be closed, creating the 21 CFR Part 117 corrective-action record that CDI must submit to FDA.', 'SafetyChain does not provide a scientific validation service for the EMP itself — CDI must engage a qualified food safety authority (e.g., a PCQI) to validate the monitoring plan design before using SafetyChain to execute it.', 'SafetyChain''s verified capabilities map tightly to the claimed MCs (HACCP monitoring, Pre-Op hygiene, CAPA workflows) and the incident''s food-safety contamination scenario is precisely the category the platform is built for, but evidence rests on product-page copy and one framework alignment with no named customer case studies, and the platform''s strong food-manufacturing brand recognition introduces modest reputation-halo risk.'),
  (12, 11, 3, 'Neogen Analytics Environmental Monitoring Program (powered by Corvium)', 'Neogen provides food safety testing products and an analytics environmental monitoring programme platform (powered by Corvium) that enables remote monitoring of multiple processing plant sites, centralises environmental testing data, and automates reporting for compliance and corrective-action conformance.', 'https://www.dairyfoods.com/articles/94959-neogen-makes-its-environmental-monitoring-program-available-at-no-cost', 'Risk Coverage', 'enabler', 'MC-OPS-005', '{"MC-OPS-005"}', 58, 'DIRECTIONAL', 'full', 'Neogen''s analytics EMP platform centralises environmental test results from CDI''s Visalia processing zones into a single dashboard accessible remotely, eliminating the paper-based or siloed swab result recording that typically delays detection of harborage events. By automating compliance and conformance reporting, the platform produces a continuous record of Salmonella-targeted environmental monitoring that constitutes the ''at least one completed monitoring cycle with results on file'' documentation required by MC-OPS-005 before CDI may restart commercial shipments. The platform''s multi-site capability means CDI can monitor all implicated zones simultaneously and compare zone-level performance in real time.', 'Neogen''s EMP platform does not perform accredited laboratory testing of environmental samples; CDI must use an accredited third-party laboratory for the Salmonella testing itself.; The platform does not submit the corrective action plan to FDA or obtain regulatory acknowledgement; CDI''s regulatory affairs team must manage the FDA interface.', 'Neogen''s EMP platform is genuinely adjacent to environmental monitoring that could catch Salmonella contamination events, but the verified evidence is limited to product-page-level claims with no named customer case studies, no certifications, and no framework alignments, and the platform addresses upstream monitoring prevention rather than the downstream recall cascade scenario at issue here.'),
  (13, 12, 3, 'ReposiTrak Recall Management / ReposiTrak Traceability Network', 'ReposiTrak operates the world''s largest food supply chain traceability network, enabling lot-level tracking of ingredients through the supply chain and providing a dedicated recall management solution that identifies the location of any recalled product and facilitates its removal.', 'https://repositrak.com/press-release/finally-a-faster-and-more-precise-recall-solution-for-the-food-supply-chain-industry/', 'Risk Coverage', 'enabler', 'MC-OPS-029', '{"MC-OPS-029","MC-OPS-030","MC-TPR-021"}', 78, 'INFERRED', 'full', 'ReposiTrak''s Recall Management solution leverages its existing lot-level traceability infrastructure to give CDI a real-time view of where every implicated bulk NFDM and Buttermilk Powder lot has been received, maintaining virtual inventory status from distribution centre to store. When CDI or FDA needs to identify all unconfirmed downstream consignees, a simple lot-code search surfaces the complete trace-back, enabling CDI to build and update the real-time consignee registry required by MC-OPS-029. For downstream manufacturers (MC-OPS-030), ReposiTrak''s Traceability Network links CDI''s lot codes to finished-product batch records at those manufacturers'' facilities, enabling the 24-hour traceability drill required by AC-OPS-030-RCL-01. The FSMA 204-aligned KDE recordkeeping obligations embedded in the network also satisfy the distributor lot-level consignee record requirements of MC-TPR-021.', 'ReposiTrak does not provide FDA regulatory submission services; CDI must separately submit the consignee data to FDA recall coordinators formatted to agency requirements.', 'ReposiTrak''s lot-level traceability and recall management capabilities map precisely to the downstream cascade scenario (MC-OPS-029/030, MC-TPR-021), with four verified product-page claims corroborating coverage, but the absence of named customer case studies, zero verified certifications, and a single framework alignment cap evidence strength and introduce moderate reputation-halo risk given the ''world''s largest'' positioning.'),
  (14, 10, 3, 'SafetyChain Food Safety Programs – Material and Incoming Programmes', 'SafetyChain is a digital plant management platform that digitises receiving inspections and material control programmes with automated escalation and CAPA-driven follow-up, enabling documented lot-level hold and segregation management for implicated ingredient batches.', 'https://safetychain.com/platform/food-safety-programs', 'Risk Coverage', 'enabler', 'MC-OPS-014', '{"MC-OPS-014"}', 62, 'INFERRED', 'partial', 'SafetyChain''s material and incoming programmes platform captures receiving inspection data at the point of receipt and, when a hold flag is triggered for an implicated lot, automatically escalates the material issue to QA leadership with a CAPA task. The platform''s centralized records and audit history provide the lot-level segregation documentation dossier — receiving records, inspection results, hold status — that CDI must make available to FDA inspectors within 24 hours of request under MC-OPS-014.', 'SafetyChain does not control CDI''s warehouse management or ERP system; physical lot segregation and the inventory system HOLD flag must be implemented in those systems separately.', 'SafetyChain''s verified receiving-inspection and CAPA workflow capability maps well to MC-OPS-014 lot-level hold and segregation needs, but evidence rests on a single product-page claim with no named customer references, no certifications, and the platform''s relevance to the downstream cascade scenario is adjacent rather than direct—addressing upstream intake controls rather than the multi-SKU downstream traceability and recall coordination that defines this incident''s severity.'),
  (15, 13, 3, 'Food and Drink Recall Management', 'Sedgwick is the world''s leading product recall management company, providing end-to-end recall management services for food and drink brands including regulatory compliance, consumer notification, retailer coordination, consignee identification and management, product retrieval, and real-time recall reporting.', 'https://www.sedgwick.com/product-recall/industries/food-and-drink/', 'Incident Handler', 'implementor', NULL, '{}', 82, 'INFERRED', 'full', 'Following CDI''s April 20, 2026 voluntary recall, Sedgwick''s food and drink recall team deploys its end-to-end recall management capability: it takes over consignee identification and management, using data-driven strategies and real-time reporting to build and update the registry of all downstream SKUs — including the Utz, Ghirardelli, and Jonco cascade products. Sedgwick manages multi-channel outbound communications to impacted retailers (Target, Walmart, Aldi) and consumers via its contact centre, coordinates product retrieval from retail shelves, and uses its proprietary data management system to provide CDI with real-time tracking and the precise recall reporting documentation needed for weekly 21 CFR Part 7 status submissions to FDA. For the non-regulatory food safety advisory elements, Sedgwick also handles precautionary safety advisories and voluntary withdrawals for downstream co-manufacturers that need to respond to the cascade.', 'Sedgwick does not provide the validated environmental monitoring programme (MC-OPS-005) or root-cause analysis (MC-OPS-025) required before CDI may resume commercial shipments; those are food safety and regulatory advisory services outside Sedgwick''s recall management scope.', 'Sedgwick is a near-perfect functional match — 30+ years in food pathogen recalls, explicit multi-SKU downstream cascade capability, and 7,000+ programmes executed — but the evidence base is product-page claims and scale metrics rather than named customer case studies, preventing a DOCUMENTED rating despite the capability alignment being essentially exact.'),
  (16, 14, 3, 'Deloitte Product Traceability and Transparency Services / Product Lifecycle Management', 'Deloitte''s Future of Food Programme provides food traceability, product lifecycle management, and regulatory compliance advisory services to food manufacturers, helping them establish digital lot-level traceability, comply with FSMA Section 204, and accelerate recall response through faster identification of affected supply chain partners.', 'https://www.deloitte.com/us/en/industries/consumer/about/deloitte-food-and-product-safety-services.html', 'Incident Handler', 'implementor', NULL, '{}', 62, 'INFERRED', 'partial', 'Deloitte''s advisory engagement post-California Dairies recall would focus on establishing the physical-to-digital traceability infrastructure CDI currently lacks: data standardisation across CDI''s wholesale distributor agreements to ensure lot-level KDE records are accessible to FDA within 72 hours (MC-TPR-021), and technology-enablement to close the process gaps that caused multi-week delays before downstream manufacturers filed their own recalls (MC-OPS-030). Deloitte''s Product Lifecycle Management service also addresses the financial and operational impact of the recall cascade, helping CDI quantify the inventory write-off exposure and design the contractual remediation strategy for downstream supply agreements.', 'Deloitte does not operate a live recall management execution service (consignee notification, product retrieval, contact centre); those require an operational recall firm.; Deloitte does not provide the validated environmental monitoring programme or root-cause analysis advisory specific to Salmonella contamination in dairy powder manufacturing — those require a food safety technical consultancy.', 'Deloitte''s verified capability claims align well with the post-recall traceability remediation and FSMA 204 compliance scenario, but evidence rests entirely on product-page marketing copy with no named customer references or case studies, and the major-consultancy reputation halo introduces meaningful selection-bias risk against more specialised implementors.'),
  (17, 15, 4, 'CrowdStrike Falcon® Insight XDR – Automated Remediation', 'CrowdStrike Falcon Insight XDR is a cloud-native endpoint detection and response platform that uses behavioral AI and indicators of attack (IOAs) to detect malicious processes, automatically remove artifacts dropped by malware, kill associated processes, and network-contain compromised developer workstations before CI/CD credential exfiltration can occur.', 'https://www.crowdstrike.com/tech-hub/endpoint-security/crowdstrikes-automated-remeditaion/', 'Risk Coverage', 'enabler', 'MC-CYB-038', '{"MC-CYB-038","MC-OPS-009"}', 72, 'INFERRED', 'full', 'Falcon Insight XDR monitors all developer macOS endpoints via a single lightweight sensor. Upon detecting behavioral indicators matching the Nx Console 18.95.0 malware pattern — specifically the creation of com.user.kitty-monitor.plist in the user LaunchAgents directory and /var/tmp/.gh_update_state — Falcon''s automated remediation automatically quarantines the persistence artifacts, kills associated processes, and issues a network containment order isolating the endpoint from all network access including GitHub Actions runners. All remediation actions are logged in the Falcon console timeline for CISO review. Separately, Falcon Identity Protection can detect and block use of stolen PATs scraped from the compromised endpoint against GitHub''s Entra ID-connected authentication flows.', 'CrowdStrike Automated Remediation does not natively revoke GitHub PATs or npm OIDC tokens scraped from memory before the endpoint is contained; PAT revocation requires a separate SOAR integration or manual SOC action.', 'CrowdStrike''s verified EDR capabilities — behavioral IOA detection, automated remediation, and network containment of compromised endpoints — map directly to the CI/CD credential exfiltration vector in this incident, but evidence rests on product-page claims rather than named customer case studies, and the dominant-market-leader reputation introduces meaningful selection-bias risk against a purely capability-led assessment.'),
  (18, 16, 4, 'Socket for GitHub', 'Socket is a developer-first supply chain security platform that analyzes every npm (and other package manager) dependency added in a GitHub pull request for behavioral indicators of malicious code — including install scripts, obfuscated code, use of privileged shell/network/filesystem APIs, and known malware patterns — and alerts developers in the PR comment before the package enters the repository.', 'https://docs.socket.dev/docs/socket-for-github', 'Risk Coverage', 'enabler', 'MC-TPR-005', '{"MC-TPR-005","MC-TPR-021"}', 82, 'DOCUMENTED', 'full', 'Socket for GitHub integrates as a GitHub App that monitors every PR modifying package.json, package-lock.json, or yarn.lock files. For each new or updated dependency, Socket performs static behavioral analysis — not just CVE matching — to detect install scripts, obfuscated code, network exfiltration patterns, and other supply-chain attack signals. When a developer at GitHub installs or updates the Nx Console VS Code extension or any npm package, Socket detects whether the new version introduces behavioral indicators consistent with the TeamPCP pattern (preinstall hooks, obfuscated code, environment variable access). The alert is surfaced as a PR comment before the package is committed, and Socket''s CLI (ggshield-style) can also intercept bad npm install commands on developer workstations.', 'Socket for GitHub operates on package manifest changes in PRs; it does not intercept out-of-band VS Code Marketplace extension installs performed by a developer outside of a git commit workflow, such as a direct IDE extension update.', 'Socket''s verified PR-level behavioral analysis and known-malware detection capabilities map precisely to the TanStack npm supply-chain compromise vector, with real-world flagging of compromised packages like got-fetch demonstrating direct incident-type relevance, though the absence of certifications/framework alignments and moderate reputation as a known OSS security tool temper the evidence and independence scores slightly.'),
  (19, 17, 4, 'Chainguard Libraries', 'Chainguard Libraries provides a malware-resistant drop-in replacement for public npm (JavaScript), PyPI (Python), and Maven (Java) registries by rebuilding every open-source library from verified source code in a SLSA Level 3-compliant, tamper-proof build environment, attaching signed SBOMs and cryptographic provenance to every package so consumers can verify that the binary exactly matches the source and was not tampered with during build or distribution.', 'https://www.chainguard.dev/libraries', 'Risk Coverage', 'enabler', 'MC-TPR-009', '{"MC-TPR-009"}', 78, 'INFERRED', 'full', 'Chainguard Libraries integrates as a drop-in upstream registry source in JFrog Artifactory, Sonatype Nexus, or Cloudsmith, transparently serving rebuilt-from-source npm packages with SLSA L3 provenance and signed SBOMs. When a GitHub Actions pipeline installs @tanstack or any other npm namespace package, it receives the Chainguard-rebuilt binary — which was compiled from the original verified source repository in a hardened build environment — rather than the public registry artifact. Because the binary is rebuilt from source rather than distributed from the maintainer''s publishing credentials, a TeamPCP compromise of the nrwl/nx or @tanstack publisher account cannot inject malicious code into what GitHub''s internal pipelines receive. Every package ships with Sigstore signatures and a signed SBOM that CI/CD tooling can verify before execution.', 'Chainguard Libraries currently covers 17K+ JavaScript npm packages but does not rebuild every package in the npm registry; packages not yet in the Chainguard namespace fall back to public registry trust unless the customer configures a hard block.', 'Chainguard''s SLSA L3-compliant, built-from-source npm registry is a precise technical match to the TanStack/Nx Console supply chain poisoning vector, with verified product-page claims covering 98%+ malware elimination and signed SBOM provenance, but the absence of named customer case studies, zero verified certifications or framework alignments, and the inherent reputation halo of a well-funded vendor in a high-profile space temper the evidence strength and independence scores.'),
  (20, 18, 4, 'Mandiant Incident Response Service / Compromise Assessment', 'Mandiant provides enterprise incident response services including in-depth attack analysis, CI/CD pipeline forensics, breach remediation, crisis communications planning, and compromise assessment — covering the full response lifecycle from triage to recovery with on-call incident responders available within a two-hour SLA under a Mandiant Retainer.', 'https://www.mandiant.com/services/incident-response', 'Incident Handler', 'implementor', NULL, '{}', 72, 'INFERRED', 'full', 'Upon retainer activation following the May 21 disclosure, Mandiant deploys on-call incident responders within two hours to begin GitHub CI/CD forensics: reconstructing the full attack chain from the poisoned Nx Console 18.95.0 install, through credential scraping, to OIDC token issuance and the bulk clone of ~3,800 repositories. Mandiant conducts a compromise assessment to identify any additional attacker activity, lateral movement, or persistence mechanisms not yet discovered. Simultaneously, Mandiant''s cyber crisis communications team coordinates the CISO''s public statement with Microsoft corporate communications, develops downstream customer breach notification playbooks (MC-REP-008), and manages the CIRCIA 72-hour reporting timeline.', 'Mandiant is an incident response services firm, not a product vendor; its engagement is reactive rather than preventive and does not provide the software controls (EDR, SLSA provenance, allow-list policy) required by the preventive MCs.', 'Mandiant''s verified capabilities directly map to the CI/CD forensics, breach remediation, and crisis communications required by this incident, but evidence rests on product-page claims rather than named case studies, and the high score partly reflects Mandiant''s market reputation rather than incident-specific demonstrated performance.'),
  (21, 19, 4, 'Unit 42 Incident Response – Supply Chain / CI/CD Compromise', 'Unit 42 is Palo Alto Networks'' threat intelligence and incident response team, providing DFIR services for supply chain compromises with deep-bench expertise specifically on TeamPCP and the Shai-Hulud worm campaigns — including documented threat intelligence, XQL hunting queries, and Cortex XDR/XSIAM detection rules specific to TeamPCP TTPs.', 'https://unit42.paloaltonetworks.com/teampcp-supply-chain-attacks/', 'Incident Handler', 'implementor', NULL, '{}', 74, 'INFERRED', 'full', 'Unit 42''s IR team brings adversary-specific intelligence on TeamPCP TTPs to the GitHub forensic investigation — including the exact file artifacts (kamikaze.sh, kube.py, tpcp.tar.gz, pglog, .pg_state), C2 domains (scan.aquasecurtiy[.]org, checkmarx[.]zone, models.litellm[.]cloud), and XQL hunting queries covering TeamPCP process execution, file creation, and network exfiltration patterns. This intelligence immediately cuts the dwell-time analysis phase compared to a general IR firm. Unit 42 also provides interim guidance on GitHub Actions hardening (npm ci, lockfile enforcement, egress restriction on CI runners) that can be operationalised immediately during the response.', 'Unit 42''s XQL hunting queries are optimised for Cortex XDR/XSIAM customers; GitHub would need to translate these queries to its own SIEM tooling if it is not a Cortex customer.', 'Unit 42''s adversary-specific TeamPCP threat intelligence and XQL hunting queries are a near-exact match to the incident scenario, but evidence anchors are product/blog pages rather than named GitHub or peer customer case studies, and Palo Alto''s dominant brand reputation introduces meaningful selection-bias risk that caps the independence score.'),
  (22, 20, 5, 'BigID Data Intelligence Platform – Biometric Data Security', 'BigID provides an AI and machine-learning-based data intelligence platform that discovers, classifies, and protects sensitive data including biometric identifiers across structured and unstructured data stores at petabyte scale.', 'https://bigid.com/blog/biometric-data-security/', 'Risk Coverage', 'enabler', 'MC-DAT-015', '{"MC-DAT-015","MC-DAT-025"}', 68, 'INFERRED', 'full', 'BigID discovers all instances of biometric fingerprint and palm-print data across NYCHHC''s structured and unstructured data stores using its Hyperscan engine and ML-based classifier, then classifies them as a distinct highest-sensitivity tier. Once classified, BigID enforces per-field access policies that require elevated authorisation before any third-party account is provisioned with read, copy, or query access to systems containing those fields. The platform continuously monitors access to biometric data stores and flags overly permissive permissions for immediate remediation, and enables automated deletion workflows for records beyond their retention period.', 'BigID does not itself constitute the board-level governance committee required to approve third-party biometric access; the customer must establish that governance structure and configure BigID''s approval workflows to route to the designated board-level delegate.', 'BigID''s verified capabilities map directly to biometric data discovery, classification, access-rights remediation, and HIPAA/NIST alignment—closely matching the DAT controls and breach scenario—but scores are moderated by evidence resting entirely on vendor product-page claims with no named customer case studies, zero verified certifications, and a reputation-halo risk given BigID''s market prominence in data intelligence.'),
  (23, 20, 5, 'BigID Data Intelligence Platform – Healthcare Data Security', 'BigID provides an ML-based data intelligence platform that enables healthcare organisations to discover, classify, and monitor access to PHI including biometric data, and to operationalise incident response workflows identifying exactly whose data was impacted in a breach.', 'https://bigid.com/blog/healthcare-cybersecurity-best-practices/', 'Risk Coverage', 'enabler', 'MC-DAT-016', '{"MC-DAT-016","MC-DAT-024"}', 72, 'INFERRED', 'partial', 'BigID''s file-access monitoring module provides permission-level visibility over PHI data stores, identifying accounts — including vendor accounts — with access to large sensitive datasets and surfacing overexposed data for remediation. When a breach occurs, BigID''s incident response feature accelerates the identification of exactly which individuals'' biometric and medical records were accessed, enabling the healthcare organisation to distinguish affected biometric-data subjects (who require lifetime fraud monitoring) from affected credential holders (who can rotate credentials). This directly supports both the DLP layer required by MC-DAT-016 and the biometric-specific incident response protocol required by MC-DAT-024.', 'BigID''s file-access monitoring is not a real-time network DLP solution; it provides permission-analysis and post-access visibility rather than inline blocking of bulk-copy sessions. Dedicated network DLP tooling is required to generate real-time egress alerts for the 77-day bulk-copy pattern in the NYCHHC incident.', 'BigID''s verified capabilities map directly to the claimed controls (PHI discovery, access analysis, incident scoping) and the breach scenario (biometric/PHI exfiltration, identifying impacted individuals), but evidence rests on product-page claims rather than named customer case studies, and no certifications are verified, limiting confidence beyond INFERRED.'),
  (24, 21, 5, 'Delinea PAM for Healthcare Organizations', 'Delinea provides a privileged access management platform purpose-built for healthcare organisations that enforces just-in-time privilege elevation, session monitoring, role-based access controls, and MFA for all third-party vendor accounts with access to ePHI systems.', 'https://delinea.com/solutions/privileged-access-management-for-healthcare-organizations', 'Risk Coverage', 'enabler', 'MC-CYB-028', '{"MC-CYB-028","MC-CYB-015"}', 74, 'INFERRED', 'full', 'Delinea replaces persistent third-party vendor credentials with just-in-time PAM sessions that require MFA at each elevation, automatically expire after the session window, and produce full session logs retained for audit. For NYCHHC, this means the unnamed vendor''s compromised credential — which persisted undetected for 77 days — would instead have been a time-bounded session revoked at expiry, preventing dwell-time accumulation. Delinea also enforces least-standing privilege at the server level via Server PAM, preventing lateral movement across NYCHHC''s 70-location network even if a single vendor credential was compromised.', 'Delinea PAM controls vendor access at the credential and session layer but does not provide network segmentation enforcement at the firewall or SDN layer; additional network segmentation tooling is required to prevent east-west movement across NYCHHC''s 70-location environment.', 'Delinea''s healthcare-specific PAM capabilities (JIT privilege elevation, third-party vendor session monitoring, MFA at privilege gates) map precisely to the third-party vendor access vector in this incident, but evidence rests primarily on vendor-commissioned material and product pages rather than independent named-customer validation, and the single framework alignment without certifications limits both evidence strength and independence scores.'),
  (25, 22, 5, 'Exabeam New-Scale Analytics – UEBA', 'Exabeam provides a cloud-native SIEM and UEBA platform that builds behavioural baselines for every user and entity — including vendor accounts — and applies risk-based anomaly detection to flag deviations such as bulk data access, off-hours activity, and access outside contracted scope.', 'https://www.exabeam.com/capabilities/ueba/', 'Risk Coverage', 'enabler', 'MC-CYB-029', '{"MC-CYB-029"}', 62, 'INFERRED', 'full', 'Exabeam New-Scale Analytics ingests session logs for all vendor-originated sessions in NYCHHC''s environment and builds per-vendor behavioural baselines covering typical access hours, data-copy volumes, and system access patterns. Once a vendor session deviates from baseline — such as initiating bulk-copy operations on PHI stores outside contracted scope, or sustaining elevated data-read volumes for multiple consecutive hours — Exabeam''s risk-scoring engine escalates the risk score and automatically opens a case for SOC investigation, with a machine-built timeline showing the full scope of anomalous activity. Applied retrospectively to the NYCHHC breach window, this detection model would have flagged the vendor session within hours of the first bulk-copy event rather than the 69-day gap.', 'Exabeam''s UEBA detection requires structured log data from NYCHHC''s session management and network access systems; if vendor sessions are not logged at the required granularity (e.g. file-level access events rather than session-level events), the anomaly detection cannot be calibrated to detect bulk-copy volumes accurately.', 'Exabeam''s UEBA and behavioral baselining directly target the third-party/vendor-account anomaly detection gap relevant to this breach, but evidence is limited to product-page claims with no named customer case studies, and the vendor''s broad SIEM reputation introduces some halo effect against a moderately specific incident match.'),
  (26, 23, 5, 'SecurityScorecard TITAN AI – TPRM / Healthcare Supply Chain', 'SecurityScorecard provides an AI-powered third-party risk management platform that uses real-time threat intelligence and predictive analytics to continuously monitor vendor security postures, identify indicators of compromise at vendor network perimeters, and reduce the time to identify vendor breaches from weeks to hours.', 'https://securityscorecard.com/blog/securing-your-healthcare-supply-chain-guide-to-tprm/', 'Risk Coverage', 'enabler', 'MC-TPR-024', '{"MC-TPR-024","MC-TPR-001"}', 52, 'DIRECTIONAL', 'full', 'SecurityScorecard''s TITAN AI platform establishes a continuous-monitoring programme for NYCHHC''s Tier 1 vendors by ingesting real-time threat intelligence feeds and mapping each vendor''s external-facing infrastructure against known indicators of compromise, active ransomware campaigns, and credential exposure events. For each monitored vendor, TITAN generates a predictive breach-likelihood score updated continuously rather than annually, and triggers autonomous remediation workflows — such as restricting vendor network access — immediately upon detecting high-risk signals without waiting for vendor response. The platform''s blast-radius mapping capability can identify which NYCHHC-connected vendors are exposed to a new CVE within hours of publication, directly addressing the 3–14 day identification gap that characterised the NYCHHC pre-breach period.', NULL, 'SecurityScorecard''s continuous third-party monitoring capability is directly adjacent to the MC-TPR controls and the vendor-originated breach scenario, but evidence is limited to a single product-page claim with no verified customer references or certifications, and the platform''s reputation as a well-known brand introduces meaningful halo bias that is not offset by independent validation.'),
  (27, 24, 5, 'Kroll Identity Monitoring and Data Breach Notification Services', 'Kroll provides data breach notification, identity monitoring, and credit monitoring services for organisations responding to breaches, with licensed investigators monitoring PII including medical ID numbers and SSNs for identity theft indicators beyond what credit monitoring alone would detect.', 'https://www.kroll.com/en/services/cyber/notification-monitoring/identity-monitoring', 'Incident Handler', 'implementor', NULL, '{}', 84, 'DOCUMENTED', 'partial', 'Kroll''s breach notification team drafts and distributes multi-jurisdictional notification letters for the 1.8 million affected NYCHHC individuals, operationalising the HIPAA Breach Notification Rule 60-day deadline and the NY SHIELD Act requirements. Its identity monitoring platform then monitors each affected individual''s SSN, Medical ID Number, bank account numbers, and PII on dark-web sources and public records databases — detecting identity theft indicators that would not appear in credit reports for months or years after the breach. Licensed Kroll investigators are available 24/7 to assist individuals who detect suspicious activity, providing restoration services for confirmed identity theft.', 'Kroll''s standard identity monitoring offering is time-bounded (NYCHHC has offered 24 months) and does not address the lifetime biometric fraud monitoring obligation that arises from the irrevocable theft of fingerprint and palm-print scans; a separate biometric-specific monitoring service is required for that obligation.', 'Kroll is directly named as the active implementor for this exact incident with verified capability in medical ID monitoring — the primary fraud vector for biometric/medical record theft — and 23% healthcare breach share confirms sector leadership, with minor score reduction reflecting that evidence anchors are product-page and proprietary-stat claims rather than independent named case studies.'),
  (28, 25, 6, 'HighRadius AI-Powered Credit Management Software', 'HighRadius provides an AI-driven credit scoring and monitoring platform that continuously tracks payment behavior, Days Beyond Terms, and adverse financial events for B2B customer portfolios, generating early-warning alerts when deterioration is detected.', 'https://www.highradius.com/software/order-to-cash/credit-management/credit-scoring-and-risk-assessment-automation/', 'Risk Coverage', 'enabler', 'MC-TPR-021', '{"MC-TPR-021","MC-TPR-023"}', 67, 'INFERRED', 'enabling', 'HighRadius ingests ERP payment history, bureau feeds, financial statements, and behavioral signals into a unified AI scoring engine that continuously recalibrates Probability of Default (PD), Risk Class, and Credit Limit recommendations. When a counterparty''s payment behavior deteriorates — analogous to the Saks Global DBT trajectory rising from 16.43% to 45.33% — the engine automatically detects the drift, updates the credit score, adjusts the risk tier, and surfaces an alert to the credit team, enabling a documented credit-exposure memo and exposure cap decision before further goods are shipped. The platform tracks Days Beyond Terms shifts and utilization spikes as primary early-warning signals.', 'HighRadius does not generate the legally required written CRO escalation memo or credit-exposure memorandum; it produces alerts and scoring outputs that inform the credit team, who must author the documentation themselves.; HighRadius does not perform the contractual amendment to vendor agreements required by MC-TPR-022; that requires legal counsel.', 'HighRadius maps tightly to the MC-TPR-021/023 credit monitoring controls with verified product-level claims covering bankruptcy alerts, PD-based risk tiering, and proactive limit adjustment, but evidence rests on product-page marketing copy without named customer case studies, and its selection carries meaningful reputation-halo weight as a known AR automation brand rather than a purely capability-driven pick.'),
  (29, 26, 6, 'Creditsafe Company Monitoring and Business Credit Reports', 'Creditsafe provides business credit reports and continuous company monitoring that track payment behavior, Days Beyond Terms (DBT), and credit score changes, generating real-time email alerts when a monitored counterparty''s financial profile deteriorates.', 'https://www.creditsafe.com/us/en/credit-risk/credit-reports/business-credit-reports.html', 'Risk Coverage', 'enabler', 'MC-TPR-021', '{"MC-TPR-021","MC-TPR-023"}', 62, 'INFERRED', 'enabling', 'Creditsafe provides two interlocking capabilities that address MC-TPR-021 and MC-TPR-023. First, its business credit reports track Days Beyond Terms (DBT) trajectories — the same metric that recorded Saks Global''s delinquency escalation from 16.43% to 45.33% — and include a credit score that predicts the likelihood of a business becoming seriously delinquent (90 days plus beyond terms) or bankrupt within 12 months. Second, its Company Monitoring product sends email alerts automatically when any change occurs on a monitored counterparty''s credit report, enabling the vendor to receive an early-warning signal before the counterparty files. The vendor explicitly advises reducing payment terms or requiring upfront payment if a counterparty''s credit score drops significantly.', NULL, 'Creditsafe''s DBT-tracking and real-time credit-score alert product maps directly to the early-warning signals relevant to MC-TPR-021/023 and the Saks supplier-harm scenario, but the evidence base is product-page marketing copy without named customer case studies, zero certifications or framework alignments, and Creditsafe''s selection likely carries some brand-recognition halo given the number of comparable monitoring providers, collectively capping the score at a mid-range inferred confidence.'),
  (30, 27, 6, 'Corporate Advantage Trade Credit Insurance', 'Allianz Trade provides trade credit insurance that covers vendors'' accounts receivable against losses from customer insolvency or protracted default, including monitoring of insured buyers'' financial health and indemnification when a buyer files for bankruptcy.', 'https://www.allianz-trade.com/en_US/what-is-trade-credit-insurance/our-solutions/corporate-advantage.html', 'Risk Coverage', 'enabler', 'MC-FIN-029', '{"MC-FIN-029","MC-FIN-030"}', 72, 'INFERRED', 'enabling', 'Allianz Trade Corporate Advantage provides two complementary mechanisms for the MC-FIN-029 and MC-FIN-030 controls. For MC-FIN-029, it insures the vendor''s accounts receivable against buyer insolvency: when a buyer such as Saks Global files Chapter 11, the policy indemnifies the vendor for the covered receivable balance, effectively functioning as the 100% reserve mechanism required by the control — cash is received rather than written off. For MC-FIN-030, the Ongoing Customer Analysis feature continuously monitors each insured buyer''s financial health and notifies the vendor if the buyer''s insurability changes, providing the early-warning signal that a working-capital stress test should be initiated before the plan-confirmation date.', 'Allianz Trade''s coverage is limited to receivables for which a credit limit was approved at policy inception; receivables shipped into a payment default without an approved limit may not be covered.; Allianz Trade does not provide legal advice on 503(b)(9) claims, Section 547 preference exposure, or UCC committee membership; those require a bankruptcy law firm.', 'Allianz Trade''s core product directly maps to the exact harm vendors suffered in the Saks Global bankruptcy (unpaid receivables due to customer insolvency), with verified product-page evidence for both coverage and buyer monitoring capabilities, but evidence stops at product descriptions rather than named case studies, and Allianz Trade''s brand prominence as a global insurer introduces moderate reputation-halo selection risk.'),
  (31, 28, 6, 'Bankruptcy and Restructuring – Vendor and Creditor Representation', 'Kelley Drye is a top-ranked creditor-side bankruptcy firm that responds to retail Chapter 11 filings by representing fashion vendors, trade creditors, and creditors'' committees in pursuing claims and eliminating preference and fraudulent conveyance exposure.', 'https://www.kelleydrye.com/practices/bankruptcy-and-restructuring', 'Incident Handler', 'implementor', NULL, '{}', 88, 'DOCUMENTED', 'full', 'Following the Saks Global Chapter 11 filing on January 13-14, 2026, Kelley Drye would be engaged by affected fashion vendor clients to execute a three-track response. On Track 1, the firm files 503(b)(9) administrative expense claims for goods received by Saks in the 20 days before the petition date, preserving priority-class recovery. On Track 2, it analyses all 90-day pre-petition payments received from Saks Global for Section 547 preference exposure, builds defences, and responds to any preference demand. On Track 3, it advises the vendor on whether to accept a UCC committee seat, and if accepted, represents the vendor''s interests in plan negotiations, DIP-budget approval hearings, and the June 22, 2026 plan-confirmation proceeding.', 'Kelley Drye does not perform financial modelling, working-capital stress tests, or vendor diligence analytics; those require a financial advisory firm.', 'Kelley Drye scores near-ceiling because its verified capabilities map with exceptional precision to the exact legal services fashion vendors need in the Saks Global Chapter 11 — 503(b)(9) claims, preference defense, creditors'' committee representation, and retail-specific bankruptcy experience — with the only meaningful deductions reflecting that evidence is firm-level capability attestation rather than named client case studies, and that reputation as a top-ranked firm introduces a modest halo effect alongside the genuine capability match.'),
  (32, 29, 6, 'Retail Turnaround & Restructuring Advisory', 'FTI Consulting is the self-described market leader in retail restructuring, advising companies, private equity firms, secured and unsecured creditors, and other stakeholders in both in-court and out-of-court retail restructurings and turnarounds.', 'https://www.fticonsulting.com/industries/retail-and-consumer-products/retail-turnaround-restructuring', 'Incident Handler', 'implementor', NULL, '{}', 72, 'INFERRED', 'partial', 'Following the Saks Global Chapter 11 filing, FTI Consulting could be engaged by the Official Committee of Unsecured Creditors — which includes major fashion vendor creditors — to provide financial advisory support including: detailed liquidity forecasting of the Saks estate to assess recoveries for the unsecured class; creation of vendor management programs to govern post-petition vendor relationships and DIP-funded disbursements; claims reconciliation for the 700+ vendor creditors; and serving as financial expert in plan-confirmation hearings before Judge Alfredo Perez. FTI''s documented fashion retailer CRO experience provides the context for assessing wholesale vendor exposure and liquidity under the restructuring plan.', 'FTI Consulting does not provide legal advice on 503(b)(9) administrative claims, Section 547 preference defences, or UCC committee statutory rights; those require a bankruptcy law firm.', 'FTI''s self-described market leadership in retail restructuring and documented creditor/vendor advisory work maps closely to the Saks Global Chapter 11 scenario, but the evidence base rests on a single verified product-page claim rather than named case studies, and its outsized brand reputation introduces meaningful selection-bias risk that tempers the raw capability signal.'),
  (33, 30, 7, 'Financial Industry Group – Securities Compliance and Regulatory Services', 'Fangda Partners advises financial institutions on Chinese securities regulatory compliance, licensing, and responding to regulatory enforcement actions by the CSRC and other financial regulators.', 'https://www.fangdalaw.com/en/bussiness/index14.html', 'Risk Coverage', 'implementor', 'MC-REG-008', '{"MC-REG-008","MC-REG-020"}', 79, 'DOCUMENTED', 'full', 'For MC-REG-008, Fangda''s Financial Industry Group conducts a jurisdiction-by-jurisdiction licence audit covering every UP Fintech subsidiary and associated entity conducting cross-border brokerage, fund distribution, or futures intermediation activity, benchmarked against China''s Securities Law, Securities Investment Fund Law, and Futures and Derivatives Law — the three statutes cited by the CSRC Beijing Bureau. For MC-REG-020, Fangda identifies the statutory defence window under the PRC Administrative Penalty Law, prepares and files the formal CSRC response or acceptance, and handles settlement negotiations with the CSRC based on its documented experience negotiating settlements in CSRC enforcement matters.', 'Fangda does not practice US securities law and cannot file the SEC Form 6-K required under MC-REG-020; a US-qualified firm (e.g. the top US law firm referenced in the same page) must handle that component.', 'Fangda''s verified capabilities map tightly to this exact incident type — CSRC administrative enforcement, unlicensed securities operations, and cross-jurisdictional regulatory response — with a confirmed fund-company CSRC case study anchoring the evidence, though the anonymous reference and boutique reputation factor slightly temper independence from halo bias.'),
  (34, 31, 7, 'Compliance and Investigations Practice', 'Han Kun Law Offices provides corporate compliance and government enforcement response services for Chinese and multinational companies, with documented experience in government-initiated administrative and criminal enforcement and large-scale regulatory investigations.', 'https://www.hankunlaw.com/en/portal/article/index/cid/1/id/3720.html', 'Risk Coverage', 'implementor', 'MC-REG-008', '{"MC-REG-008","MC-REG-014"}', 68, 'INFERRED', 'full', 'Han Kun''s compliance team deploys a multi-city simultaneous investigation capability to conduct the MC-REG-008 licence audit across all UP Fintech entities without information leakage, benchmarking activity in each jurisdiction against the three CSRC-cited statutes. For MC-REG-014, Han Kun''s documented experience responding to government investigations provides the legal infrastructure for the CSRC liaison protocol: designating the compliance officer point of contact, establishing the communications log, and managing all inbound and outbound CSRC Beijing Bureau communications throughout the two-year transition period with General Counsel countersignature on a bi-weekly basis.', 'Han Kun does not provide US securities law advice and cannot independently handle the SEC Form 6-K filing required under MC-REG-020.', 'Han Kun''s verified capabilities align well with CSRC enforcement response and government investigation liaison (MC-REG-008, MC-REG-014), and the incident scenario maps directly to their documented administrative enforcement practice, but evidence remains service-description-level with no named client case studies, and selection carries moderate reputation-halo risk given Han Kun''s prominence as a top-tier PRC firm.'),
  (35, 24, 7, 'Investigations, Diligence and Compliance – Financial Crime Advisory', 'Kroll provides forensic investigations, financial crime advisory, and regulatory investigation support services to financial institutions globally, with a Beijing office and a Band 1 Chambers Asia Pacific ranking for forensic accountants.', 'https://www.kroll.com/en/services/investigations-diligence-and-compliance', 'Risk Coverage', 'implementor', 'MC-FIN-016', '{"MC-FIN-016"}', 62, 'INFERRED', 'partial', 'Kroll''s forensic investigations team conducts the financial analysis required for MC-FIN-016: reviewing every credit facility, structured note, convertible instrument, and margin facility disclosed in UP Fintech''s most recent 20-F to determine whether the 23–37% single-day TIGR share decline or the RMB 411.2 million liability triggers any market-price covenant, cross-default clause, collateral-maintenance obligation, or acceleration right. Kroll''s forensic accountants in the Asia Pacific region produce the written findings report with a definitive yes/no determination for each instrument, which is then reviewed by external financing counsel for legal accuracy.', 'Kroll''s forensic accounting findings do not constitute legal opinions; the countersignature from external financing counsel confirming the legal accuracy of covenant determinations requires a licensed law firm.', 'Kroll''s forensic investigations and regulatory advisory credentials are well-credentialed for the incident category (unlicensed cross-border securities activity under CSRC), with a strong Asia Pacific footprint and Band 1 ranking, but the implementor role for MC-FIN-016 is more naturally a remediation/advisory function than a control implementation role, evidence anchors are product-page and ranking citations rather than named customer case studies, and the boutique consultancy entity type introduces some reputation-halo weighting relative to demonstrated implementation-specific capability.'),
  (36, 30, 7, 'Securities Compliance and Administrative Law Enforcement Practice', 'Fangda Partners handles administrative enforcement actions by the CSRC, including responding to investigation notices, negotiating settlement, and representing clients in administrative hearings, reconsideration, and litigation procedures arising from PRC securities regulatory enforcement.', 'https://www.fangdalaw.com/en/bussiness/index14.html', 'Incident Handler', 'implementor', NULL, '{}', 78, 'INFERRED', 'full', 'Following the 22 May 2026 CSRC penalty notice, Fangda''s response team identifies the statutory defence window under the PRC Administrative Penalty Law, prepares the formal CSRC response or acceptance, negotiates with the CSRC Beijing Bureau on transition-monitoring terms, and — given its documented experience with U.S.-listed Chinese companies facing simultaneous SEC disclosure obligations — coordinates with a US-qualified law firm on the SEC Form 6-K filing. Fangda''s team of former regulators and former members of administrative reconsideration committees provides strategic insight into how the CSRC Beijing Bureau is likely to exercise its discretion during the two-year transition period.', NULL, 'Fangda''s verified Administrative Law Enforcement team capability maps directly to CSRC administrative penalty response — the exact mechanism used against UP Fintech — with former regulator/reconsideration committee members giving strong procedural fit, but evidence rests on a single capability-page source quote with no named client case studies, and as a prominent PRC regulatory boutique some reputation halo effect cannot be excluded.'),
  (37, 32, 7, 'Litigation & Enforcement Action Communications / Financial Communications & Investor Relations', 'Teneo supports companies through high-profile regulatory enforcement actions and investor communications crises, providing integrated strategy that combines enforcement communications, investor relations, and financial communications advisory.', 'https://www.teneo.com/service/strategy-communications/litigation-enforcement-action-communications/', 'Incident Handler', 'implementor', NULL, '{}', 63, 'INFERRED', 'full', 'Following the 22 May 2026 CSRC enforcement disclosure, Teneo''s integrated crisis and investor communications team activates immediately to manage the 72-hour investor communication timeline. The team advises UP Fintech''s CEO and Head of Investor Relations on the content, structure, and distribution of the Form 6-K investor communication — covering the RMB 411.2 million liability, the CEO''s personal fine, the two-year transition timeline, and the Nasdaq listing standards maintenance plan. Simultaneously, Teneo''s crisis communications team advises on the board-level crisis protocol, including developing a single approved narrative for Tiger Brokers client-facing communications in non-PRC markets and a briefing document for institutional equity analysts, ensuring the company is not conflated with the concurrent Futu Holdings CSRC enforcement action.', 'Teneo does not practice PRC or US securities law and cannot independently prepare the legal content of the CSRC formal response or the SEC Form 6-K; those require licensed legal counsel.', 'Teneo''s verified capabilities closely match the enforcement communications and investor relations requirements of this CSRC penalty scenario, but evidence rests on marketing-copy capability claims without named case studies or China-specific regulatory enforcement track record, and the APAC/CSRC jurisdictional fit remains undemonstrated.'),
  (38, 33, 7, 'Risk, Regulatory & Forensic', 'Deloitte China''s Risk, Regulatory & Forensic practice helps financial institutions respond to specific enforcement events by building remediation programmes, managing regulatory nuances, and deploying advanced data analysis and modelling to reduce financial risk and restore compliance.', 'https://www.deloitte.com/cn/en/services/consulting/services/risk-regulatory-forensic.html', 'Incident Handler', 'implementor', NULL, '{}', 62, 'INFERRED', 'partial', 'Following the 22 May 2026 CSRC penalty disclosure, Deloitte China''s Risk, Regulatory & Forensic team provides three response streams: (1) financial modelling support for the RMB 411.2 million provision and covenant-breach analysis under MC-FIN-004 and MC-FIN-016; (2) compliance programme remediation to implement the onboarding freeze, licence audit infrastructure, and CSRC liaison protocol under MC-REG-004, MC-REG-008, and MC-REG-014; and (3) regulatory relationship management leveraging Deloitte China''s established regulator-trust positioning. This covers the compliance and financial risk dimensions of the incident while legal representation and investor communications are handled by specialist firms.', 'Deloitte China does not provide legal representation before the CSRC or file the SEC Form 6-K; both require qualified legal counsel.', 'Deloitte China''s Risk, Regulatory & Forensic practice aligns well with the CSRC enforcement remediation scenario in terms of stated capabilities (compliance programme rebuilding, regulatory trust restoration, data analysis), but evidence rests entirely on marketing-copy capability claims with no named client case studies or certifications, and the major-consultancy brand introduces meaningful reputation-halo risk that partially offsets the genuine capability-to-scenario fit.'),
  (39, 34, 8, 'Cloudflare Web Application Firewall (WAF)', 'Cloudflare WAF inspects incoming web and API requests and filters malicious traffic — including XSS and SQL injection — using managed rulesets that are regularly updated with zero-day vulnerability protections, enabling organisations to restrict unauthenticated or malicious access to web endpoints such as OWA.', 'https://developers.cloudflare.com/waf/get-started/', 'Risk Coverage', 'enabler', 'MC-CYB-038', '{"MC-CYB-038"}', 72, 'INFERRED', 'enabling', 'Cloudflare WAF is placed in front of the OWA endpoint as a reverse proxy. The Cloudflare Managed Ruleset and OWASP Core Ruleset are deployed to detect and block XSS payloads — the attack vector for CVE-2026-42897 — before they reach the Exchange server. Additionally, the WAF can enforce Zone Lockdown or IP Access Rules to restrict the OWA URL namespace to authenticated gateway IPs only (VPN exit nodes, Azure AD Application Proxy, etc.), satisfying the MC-CYB-038 requirement to prevent unauthenticated external HTTP/HTTPS access to OWA. The Rules language supports custom WAF Attack Score thresholds for Enterprise customers.', 'Cloudflare WAF does not itself perform Exchange Health Checker verification or EEMS M2.1.x status confirmation; it addresses network perimeter access control only.', 'Cloudflare WAF directly covers XSS filtering on OWA URL namespaces via verified managed rulesets, giving strong coverage specificity and incident relevance, but evidence rests on product-page claims rather than named customer case studies, and Cloudflare''s brand prominence introduces a modest reputation-halo factor that slightly discounts the independence score.'),
  (40, 35, 8, 'BIG-IP Advanced WAF', 'F5 BIG-IP Advanced WAF is an on-premises or cloud-deployable web application firewall that uses behavioral analytics, machine learning, and the OWASP Top 10 ruleset to detect and block zero-day vulnerabilities, XSS attacks, credential theft, and application takeover against web applications including Exchange OWA endpoints.', 'https://www.f5.com/products/big-ip-services/advanced-waf', 'Risk Coverage', 'enabler', 'MC-CYB-038', '{"MC-CYB-038"}', 72, 'INFERRED', 'enabling', 'BIG-IP Advanced WAF is deployed as an on-premises reverse proxy or hardware appliance in front of Exchange Server OWA endpoints, blocking XSS payloads — the CVE-2026-42897 attack vector — using its OWASP Top 10 managed policy, behavioral analytics, and machine-learning-based attack detection. For MC-CYB-038, the product''s granular security policies can enforce authenticated-only routing of inbound OWA requests, while the learning engine continuously adapts to new evasion attempts. Its hardware deployment option makes it suitable for on-premises Exchange deployments where cloud-based WAF proxies are not permitted.', 'F5 BIG-IP Advanced WAF does not verify EEMS M2.1.x mitigation status on Exchange servers, perform EOMT execution for air-gapped nodes, or audit mailbox forwarding rules; it addresses network-perimeter access control only.', 'F5 BIG-IP Advanced WAF maps closely to this XSS/zero-day OWA scenario via verified OWASP Top 10 and behavioral analytics claims, but evidence rests on product-page marketing copy without named customer case studies, and F5''s brand reputation as a WAF leader introduces moderate selection-bias risk that tempers the independence score.'),
  (41, 36, 8, 'Duo for Outlook Web App (OWA)', 'Cisco Duo provides a dedicated OWA two-factor authentication integration that adds MFA to Exchange Server OWA logins on Exchange Server 2016, 2019, and Subscription Edition, offering inline user enrollment, self-service device management, and support for Duo Push, passkeys, and security keys via the Universal Prompt.', 'https://duo.com/docs/owa', 'Risk Coverage', 'enabler', 'MC-CYB-017', '{"MC-CYB-017"}', 62, 'INFERRED', 'full', 'Duo for OWA installs as an IIS module on the Exchange Client Access server. After a user enters their username and password, Duo intercepts the OWA authentication flow and requires completion of a second factor (Duo Push, passkey, security key, or Verified Duo Push) before an authenticated OWA session token is issued. Because CVE-2026-42897 requires an authenticated browser session to steal the session token, enforcing MFA at login significantly limits the impact: an attacker who sends a crafted email and tricks a user into opening it in OWA can only steal a session token if the user has already completed MFA — reducing the pool of exploitable sessions. Duo also supports a ''fail closed'' mode where OWA is completely inaccessible if Duo''s service is unreachable, and can suspend OWA access for accounts that cannot enrol in MFA.', 'Duo for OWA does not prevent session-token theft from an already-authenticated MFA session where a user opens a crafted email; it reduces the attack surface by requiring MFA before session establishment but cannot fully prevent post-login XSS exploitation.; Duo requires outbound TCP port 443 connectivity to Duo''s cloud service; in fail-closed mode, air-gapped Exchange nodes cannot issue OWA sessions at all when the Duo service is unreachable.', 'Duo''s OWA MFA integration is precisely matched to the affected platform (Exchange 2016/2019/SE) and directly covers the authentication layer, earning high specificity, but the XSS exploit fires before authentication completes — meaning MFA intercepts logins yet cannot neutralize a crafted-email JavaScript payload that executes inside an already-authenticated OWA session, materially limiting incident relevance and dragging D3 down.'),
  (42, 37, 8, 'Splunk Enterprise Security (ESCU — HAFNIUM Group Analytic Story)', 'Splunk Enterprise Security with the ESCU (Enterprise Security Content Update) HAFNIUM Group Analytic Story provides pre-built detection searches targeting Exchange Server OWA exploitation patterns — including W3WP.exe spawning shells, IIS log patterns indicative of OWA exploit chains, email forwarding rule creation, and post-exploitation credential dumping — directly addressing MC-CYB-019.', 'https://www.splunk.com/en_us/blog/security/detecting-microsoft-exchange-vulnerabilities-0-8-days-later.html', 'Risk Coverage', 'enabler', 'MC-CYB-019', '{"MC-CYB-019"}', 78, 'INFERRED', 'full', 'Splunk Enterprise Security with the ESCU HAFNIUM Group Analytic Story ingests Exchange HttpProxy logs, Windows Security Event Logs, and Sysmon telemetry from Exchange servers and applies pre-built detection searches targeting: (a) POST requests to OWA exploit paths in IIS/HttpProxy logs; (b) W3WP.exe spawning command shells (the primary OWA exploitation indicator); (c) ASPX webshell files written to Exchange directories post-exploitation; and (d) post-exploitation credential dumping (LSASS via ProcDump), new account creation, and lateral movement. For MC-CYB-019 specifically, the HttpProxy log ingestion guidance and OWA-path detection searches provide the SOC with the detection rules targeting OWA log patterns indicative of CVE-2026-42897-style JavaScript injection, and the W3WP shell-spawn rules detect post-exploitation execution.', 'Splunk''s ESCU HAFNIUM Analytic Story was developed for the 2021 Exchange zero-day family (CVE-2021-26855 et al.); customers must validate that SPL searches apply to CVE-2026-42897 XSS-specific indicators and may need to supplement with custom rules for session cookie reuse anomalies.; Splunk does not perform EEMS Health Checker verification, EOMT execution, or mailbox forwarding rule revocation; it is a detection and investigation platform only.', 'Three verified capability claims demonstrate highly specific SPL detections for OWA/Exchange exploitation patterns (W3WP.exe shell-spawning, IIS proxy log analysis) that map directly to CVE-2026-42897''s post-exploitation indicators, but evidence is sourced from Splunk''s own threat research blog rather than independent customer case studies, and Splunk''s dominant SIEM reputation introduces meaningful selection-bias risk that tempers the independence score.'),
  (43, 38, 8, 'Rapid7 InsightVM (Active Risk / CISA KEV) + InsightIDR (Attacker Behavior Analytics)', 'Rapid7 InsightVM provides CISA KEV-integrated vulnerability management with Active Risk scoring that automatically incorporates the CISA Known Exploited Vulnerabilities catalog into prioritised remediation, while InsightIDR''s Attacker Behavior Analytics (ABA) provides pre-built Exchange Server OWA exploitation detections used by Managed Detection and Response analysts to identify zero-day compromises.', 'https://www.rapid7.com/blog/post/2021/03/03/rapid7s-insightidr-enables-detection-and-response-to-microsoft-exchange-0-day/', 'Risk Coverage', 'enabler', 'MC-CYB-036', '{"MC-CYB-036","MC-REG-004"}', 84, 'DOCUMENTED', 'partial', 'Rapid7 InsightVM identifies Exchange Server 2016, 2019, and SE instances across the on-premises estate and automatically tags CVE-2026-42897 (as a CISA KEV-listed vulnerability) with elevated Active Risk scores — supporting MC-REG-004 by providing FCEB agencies with a prioritised, evidence-based remediation queue. InsightIDR''s ABA detections flag the behavioural indicators of Exchange OWA exploitation (webshell uploads to OWA paths, IIS log anomalies, credential-dumping post-exploitation) that correlate with EEMS mitigation verification failures, supporting MC-CYB-036 by alerting administrators to compromises on servers where EEMS M2.1.x has not been verified. The MDR service layer provides 24/7 analyst oversight of these detections.', 'Rapid7 does not perform GDPR Article 33 breach assessments or mailbox forwarding rule audits; its scope is vulnerability management and threat detection.', 'Rapid7 scores highly because verified capability claims document pre-patch Exchange OWA zero-day detection via InsightIDR ABA with MDR-identified webshell uploads and attacker techniques, directly matching the incident scenario, while InsightVM''s CISA KEV integration addresses MC-CYB-036 prioritisation; minor deductions reflect that CVE-2026-42897 post-dates Rapid7''s documented Exchange responses (creating an inference gap), evidence lacks named customer citations, and Rapid7''s market prominence introduces modest reputation-halo risk.'),
  (44, 39, 8, 'OneTrust Incident & Breach Response', 'OneTrust Incident & Breach Response is a privacy management platform that enables organisations to manage the full lifecycle of personal data incidents — including GDPR Article 33 supervisory authority notification — with automated workflows powered by Databreachpedia™ Global Law Engine integrating hundreds of region-specific breach notification laws.', 'https://www.onetrust.com/news/onetrust-enhances-incident-breach-response/', 'Risk Coverage', 'enabler', 'MC-REG-016', '{"MC-REG-016"}', 55, 'DIRECTIONAL', 'full', 'OneTrust Incident & Breach Response enables the Data Protection Officer or privacy lead to initiate a structured GDPR Article 33 breach-likelihood assessment directly within the platform following the CVE-2026-42897 disclosure. The Databreachpedia™ engine automatically applies GDPR Article 33''s 72-hour supervisory authority notification requirement based on the jurisdiction of affected EU-resident mailbox holders, generating a pre-configured assessment workflow. If the DPO determines that a personal data breach cannot be ruled out, the platform generates a supervisory authority notification document and tracks the filing deadline with automated reminders. The full audit trail — breach/no-breach decision, rationale, and notification filing reference — is retained as a GDPR accountability record.', 'OneTrust does not perform forensic investigation of Exchange server logs, mailbox session analysis, or EEMS mitigation verification; the platform provides legal/compliance workflow support only.', 'OneTrust precisely covers the regulatory notification lifecycle (MC-REG-016 / GDPR Art.33 72-hour window) making it a strong fit for the enabler role on that narrow compliance dimension, but the incident is a CYB severity-4 zero-day XSS exploit where the primary gap is technical detection/containment rather than breach-notification workflow, the evidence base is marketing-page product claims without named customer references or third-party validation, and the incident category mismatch (active exploitation response vs. notification management) substantially limits D3 and overall score.'),
  (45, 40, 8, 'CrowdStrike Falcon Complete / CrowdStrike Incident Response Services', 'CrowdStrike provides Falcon Complete managed detection and response and on-demand Incident Response Services that have documented real-world experience detecting, containing, and remediating Microsoft Exchange Server OWA zero-day exploitation, including webshell removal, IIS log forensics, and post-exploitation artefact remediation.', 'https://www.crowdstrike.com/en-us/services/incident-response/', 'Incident Handler', 'implementor', NULL, '{}', 88, 'DOCUMENTED', 'full', 'Following detection of CVE-2026-42897 exploitation, CrowdStrike deploys its Critical Escalation Playbook: Falcon Complete analysts network-contain compromised Exchange servers, use Real-Time Response (RTR) to enumerate and remove webshells from IIS directories, analyse IIS and ECP server logs to reconstruct the exploitation chain, and conduct endpoint memory forensics to identify injected DLLs. The OverWatch proactive threat-hunting team provides early visibility into novel exploitation patterns — as it did for the Exchange zero-days in 2021 — before threat signatures are publicly available. The IR service also monitors for post-exploitation artefacts including email forwarding rules consistent with MC-DAT-013.', NULL, 'Two verified capability claims document CrowdStrike Falcon Complete''s direct, operational response to Exchange OWA zero-day mass exploitation — including MSExchangeOWAAppPool process-tree detection, webshell removal, and IIS/ECP log forensics — an exact scenario match that drives near-maximum D1 and D3 scores, with D2 slightly discounted for absence of named customer references and D4 modestly penalised given CrowdStrike''s brand weight in MDR/IR markets.'),
  (46, 41, 8, 'Mandiant Incident Response Services / Mandiant Retainer', 'Mandiant provides incident response and compromise assessment services for breaches and active exploitation scenarios, deploying on-call incident responders globally within hours to conduct in-depth attack analysis, containment, forensic investigation, and full breach remediation.', 'https://cloud.google.com/security/consulting/mandiant-incident-response-services', 'Incident Handler', 'implementor', NULL, '{}', 72, 'INFERRED', 'full', 'Following CVE-2026-42897 exploitation, Mandiant deploys on-call incident responders to conduct in-depth forensic analysis of Exchange IIS logs, ECP logs, and mailbox session data to identify the scope of compromise — including which mailboxes were impersonated, which session tokens were stolen, and whether attacker-planted forwarding rules exist (MC-DAT-013, MC-CYB-001). The Compromise Assessment service specifically searches for previously unseen attacker activity and identifies configuration weaknesses, supporting both the forensic investigation of the active exploitation and the GDPR Article 33 breach scope determination (MC-REG-016). The 2-hour Retainer response time enables rapid engagement within the CISA KEV remediation window.', 'Mandiant does not directly run the Exchange Health Checker script or execute EOMT on the customer''s behalf; those Exchange administrator tasks are guided by Mandiant recommendations but performed by the customer.; Mandiant does not file GDPR supervisory authority notifications or produce the CISA KEV BOD 22-01 attestation documentation; those regulatory compliance actions require the customer''s DPO and compliance officer.', 'Mandiant''s IR and Compromise Assessment services are a strong, direct fit for active Exchange zero-day incident handling, with verified capability claims matching the scenario well, but scores are tempered by product-page-level evidence only (no named case studies), zero verified certs/framework alignments, and a significant reputation-halo factor given Mandiant''s brand prominence as a top-tier IR consultancy.'),
  (47, 42, 9, 'Wildlife Oil Spill Response Services – GOWRS and Sea Alarm', 'OSRL provides wildlife response services covering oiled birds, mammals, and reptiles through partnerships with Sea Alarm (strategic and tactical advice) and the Global Oiled Wildlife Response System (GOWRS) (in-field expert assessment teams), with pre-positioned wildlife response equipment for rapid deployment.', 'https://www.osrl.com/services/response/wildlife/', 'Risk Coverage', 'enabler', 'MC-ENV-019', '{"MC-ENV-019","MC-ENV-020"}', 62, 'INFERRED', 'partial', 'Upon activation through the OSRL Duty Manager, Sea Alarm provides immediate strategic and tactical advisory on wildlife response management for the cetacean, avian, and fish mortality documented along the Sochi–Anapa coastline. In parallel, GOWRS deploys a four-person expert team within four days to conduct an in-field oiled wildlife assessment, producing a written report with recommendations for full-scale mobilisation including rehabilitation centre capacity. OSRL''s pre-positioned Tier 3 wildlife response equipment — covering field collection, medical, cleaning, and rehabilitation needs — is deployed to support initial response operations at the Anapa and Tuapse staging areas.', 'OSRL''s wildlife assessment via GOWRS produces a written report with recommendations rather than a full IUCN rapid-assessment protocol compliant biodiversity impact assessment; the AC-ENV-019-ESG-01 requirement for a 45-day full assessment with cetacean specialist, marine ornithologist, and ichthyologist would require additional specialist contracting.', 'OSRL''s verified wildlife response capabilities (Sea Alarm, GOWRS, real-time monitoring, habitat protection) map well to ENV controls and a coastal oil spill scenario, but evidence rests on product-page-level claims with no named case studies, the Tuapse incident''s geopolitical/access complexity limits practical deployability, and as a well-known industry cooperative its selection carries moderate reputation-halo risk.'),
  (48, 43, 9, 'Wildlife Response Services', 'Sea Alarm is an NGO that provides strategic and tactical advisory, on-site management support, and international resource mobilisation for oiled wildlife emergencies globally, with documented response to a large number of marine oil spill incidents involving birds and marine mammals.', 'https://www.sea-alarm.org/our-work/response/', 'Risk Coverage', 'implementor', 'MC-ENV-019', '{"MC-ENV-019","MC-ENV-020"}', 62, 'INFERRED', 'partial', 'Sea Alarm operates across three escalating mobilisation levels: Level 1 provides remote advisory connecting the client with specialist experts for initial cetacean, avian, and ichthyofauna mortality guidance; Level 2 deploys Sea Alarm staff on-site with one or two experts to conduct an in-field assessment; Level 3 identifies and mobilises full international expert teams via EUROWA (European network with Belgium-based equipment stockpile) and GOWRS (global network). For the Sochi–Anapa cetacean and avian mortality event, Sea Alarm would progress through levels 1 to 3, identifying and integrating cetacean specialists and marine ornithologists into the response team and ensuring wildlife rehabilitation capacity at Anapa centres is adequate.', 'Sea Alarm''s Level 3 response is conditional on adequate funding being in place; the response cannot be mobilised without a confirmed response budget.', 'Sea Alarm''s oiled wildlife advisory and international resource mobilisation capabilities align well with MC-ENV-019/020 implementor needs, but verified evidence is limited to self-sourced claims with no named case studies, the Black Sea incident''s conflict-zone and refinery-fire context adds operational complexity beyond standard spill response, and as a boutique NGO with no certified frameworks the selection carries moderate reputation-halo risk given their recognised standing in the oiled wildlife community.'),
  (49, 44, 9, 'Oil Spill Response and Preparedness – Response Services', 'International Bird Rescue maintains a professional oiled wildlife response team of emergency managers, wildlife rehabilitators, veterinarians, and biologists that deploys globally to manage bird and wildlife collection, rehabilitation, and documentation during oil spill incidents.', 'https://www.birdrescue.org/our-work/oil-spill-response-and-preparedness/services-offered/', 'Risk Coverage', 'implementor', 'MC-ENV-020', '{"MC-ENV-020"}', 78, 'DOCUMENTED', 'full', 'International Bird Rescue activates via a 24/7 Duty Manager line and deploys a Hazwoper-certified team of emergency managers, rehabilitators, veterinarians, and biologists to the incident location. The team designs and operationalises oiled wildlife rehabilitation facilities — bird-washing stations, triage, holding pools — coordinates local rehabilitators and volunteers, manages field collection, and provides veterinary medical evaluation and treatment. For the Anapa and Tuapse coastal stations, Bird Rescue would establish facility operations within days of activation, scaled to the confirmed multi-species mortality event. Documentation and cost tracking are built into every response engagement.', 'International Bird Rescue does not provide cetacean rehabilitation; marine mammal and sea otter care is referred to specialist organisations, meaning a separate cetacean triage partner is required to meet the 10-concurrent-cetacean capacity requirement of AC-ENV-020-ESG-01.', 'International Bird Rescue''s verified 50-year, 2,250-spill track record with HAZWOPER-certified teams covering oiled wildlife collection, rehabilitation, and documentation maps directly onto MC-ENV-020 implementor needs for a large coastal oil spill, with the Black Sea scenario well within their documented marine/coastal response repertoire, though absence of certified frameworks and the single-source nature of most evidence caps the score below 85.'),
  (50, 45, 9, '24/7 Operational Spill Response Assistance', 'CEDRE is a French technical institute providing 24/7 operational advisory assistance to public authorities and private companies for marine and inland water oil spill response globally, including emergency pollutant analysis, trajectory modelling, and on-site support.', 'https://cedre.fr/en/expertise/intervention', 'Risk Coverage', 'implementor', 'MC-ENV-001', '{"MC-ENV-001","MC-ENV-010"}', 72, 'INFERRED', 'partial', 'CEDRE''s laboratory and field experts can be deployed under a 24/7 assistance agreement to collect and analyse water and sediment samples from the Tuapse River and Black Sea coastal zone for petroleum hydrocarbons, benzene, xylene, and PAH — directly supporting the AC-ENV-001-ESG-01 requirement for chain-of-custody sampling at georeferenced stations. CEDRE''s trajectory models simulate oil slick drift, evaporation, and dissolution to map the 77-km contamination extent, guiding sampling station placement. On-site experts integrate with the incident management unit, providing technical recommendations on containment, monitoring, and post-spill contamination status reporting independent of Rosprirodnadzor.', 'CEDRE is a French technical institute; access to the Black Sea incident site would depend on geopolitical conditions and Russian authorities permitting foreign technical experts to operate in the Tuapse region, which is not guaranteed given the conflict context.', 'CEDRE''s verified capabilities in emergency pollutant analysis, chemical fingerprinting, trajectory modelling, and global marine/inland spill advisory align tightly with the Black Sea oil spill scenario''s technical demands, but scores are tempered by absence of certified frameworks, no named customer case studies, and the geopolitical complexity of operating in a Russian-controlled incident zone that limits realistic implementor access.'),
  (51, 45, 9, '24/7 Operational Spill Response Assistance', 'CEDRE provides 24/7 emergency technical advisory and on-site assistance for oil and chemical spills in marine and inland waters, including pollutant analysis, trajectory modelling, clean-up monitoring, and post-spill assessment for private companies and public authorities globally.', 'https://cedre.fr/en/expertise/intervention', 'Incident Handler', 'implementor', NULL, '{}', 78, 'INFERRED', 'full', 'Following the disputed 20 May 2026 cleanup declaration, CEDRE would be engaged under an assistance agreement to provide immediate remote assessment of the Tuapse contamination status, run trajectory models to estimate the current extent of the Black Sea slick, deploy on-site experts to conduct independent water and sediment sampling along the Tuapse River and coastal zone, and publish analytical results independent of Rosprirodnadzor. CEDRE''s laboratory provides emergency hydrocarbon characterisation and chemical fingerprinting to confirm or contradict the official cleanup declaration, supporting the reputational risk management requirement of CO-REP-005 and the independent baseline requirement of MC-ENV-001.', 'CEDRE''s on-site access may be limited or unavailable in the Tuapse region given the ongoing conflict context; remote advisory may be the only feasible delivery mode.', 'CEDRE''s verified capabilities map precisely to the implementor role — full-cycle spill response from alert through post-spill assessment, explicit coverage of industrial site leaks and fire-origin pollution events — but the evidence base consists of service-page claims rather than named customer case studies, and the geopolitical context (Russia, active conflict zone) introduces access and operational feasibility risk not reflected in the capability profile alone.'),
  (52, 43, 9, 'Wildlife Response Services', 'Sea Alarm is an NGO that responds to oiled wildlife emergencies globally, providing strategic advisory, on-site management, and international expert and equipment mobilisation for multi-species marine wildlife casualties following oil spill events.', 'https://www.sea-alarm.org/our-work/response/', 'Incident Handler', 'implementor', NULL, '{}', 72, 'INFERRED', 'full', 'Sea Alarm escalates through three response levels: immediate remote advisory connecting local responders with appropriate cetacean and avian specialists (Level 1); on-site visit by Sea Alarm staff with one or two experts to assess the Anapa rehabilitation centre capacity and Tuapse coastline mortality extent (Level 2); full international mobilisation of EUROWA expert teams with Belgium-stockpiled equipment and GOWRS global network resources (Level 3). Sea Alarm also coordinates linkage to P&I Club and IOPC Fund compensation mechanisms to ensure wildlife response costs are recoverable.', 'Sea Alarm''s Level 3 full mobilisation is contingent on confirmed funding availability; without a committed response budget from Rosneft or a competent authority, international expert and equipment mobilisation cannot be initiated.', 'Sea Alarm''s core mission is a precise match to the oiled wildlife implementor role (D1/D3 strong), but evidence rests on organisational self-description and network credentials rather than named incident case studies, and the geopolitical complexity of a Russian-controlled Black Sea zone introduces realistic access barriers that temper the independence score.'),
  (53, 44, 9, 'Oil Spill Response and Preparedness – Response Services', 'International Bird Rescue responds to major oil spill events globally by deploying professional teams to establish and operate oiled wildlife rehabilitation facilities, providing veterinary triage, treatment, and documentation for all oiled bird species and other wildlife.', 'https://www.birdrescue.org/our-work/oil-spill-response-and-preparedness/services-offered/', 'Incident Handler', 'implementor', NULL, '{}', 82, 'DOCUMENTED', 'full', 'Following activation, International Bird Rescue deploys a Hazwoper-certified professional team to the Anapa rehabilitation centre and a Tuapse forward staging area to design, establish, and operate oiled wildlife rehabilitation facilities. The team provides veterinary medical evaluation, triage, monitoring, and treatment for oiled seabirds, manages field collection teams along the Tuapse–Anapa coastline, recruits and trains local volunteers, and maintains systematic documentation and cost-tracking records. Cetacean rehabilitation is referred to specialist marine mammal organisations, with Bird Rescue serving as the avian response and general wildlife management lead.', 'International Bird Rescue does not rehabilitate cetaceans; marine mammal response for the dead dolphins documented near Sochi requires a separate specialist organisation.', 'International Bird Rescue''s verified 50+ year, 2,250+ spill track record with assured deployment capability maps precisely onto the oiled wildlife rehabilitation implementor role this coastal refinery spill demands, with minor score reductions for absence of formal certifications and the operational constraint that Russian Black Sea access may be practically limited given the conflict context.'),
  (54, 46, 10, 'Meltwater Media Intelligence – Crisis Monitoring', 'Meltwater provides a media intelligence platform that monitors billions of data points across online, social, print, audio, and video sources in real time, delivering keyword-triggered alerts when brand mentions surge so teams can respond to crises before they escalate.', 'https://www.meltwater.com/en/blog/crisis-monitoring', 'Risk Coverage', 'enabler', 'MC-REP-009', '{"MC-REP-009"}', 62, 'INFERRED', 'partial', 'Meltwater monitors unlimited keywords across social media, news, podcasts, and blogs and issues real-time surge alerts when any tracked keyword — such as SCK Company brand terms, 5/18 references, or ''Tank Day'' equivalents — spikes in volume. Real-time dashboards can be built to track sentiment, mention volume, and geographic distribution in the moments a crisis begins. Meltwater also allows building custom real-time dashboards so that sentiment and volume metrics are visible to the crisis response team without requiring manual platform login after an alert fires.', 'Meltwater''s documented crisis monitoring service does not enforce a mandatory acknowledgement response SLA or automatically deploy a pre-approved holding statement if no executive acknowledges within two hours; those workflow steps are customer-designed.', 'Meltwater''s verified real-time keyword surge alerts and explicit boycott-detection capability align well with MC-REP-009''s early-warning goal, but evidence rests on product-page claims rather than named customer case studies, the platform does not address the pre-launch cultural-sensitivity failure that caused the incident, and its wide market recognition introduces moderate reputation-halo risk offsetting otherwise solid coverage specificity.'),
  (55, 46, 10, 'Meltwater Media Intelligence – Crisis Monitoring', 'Meltwater provides real-time media intelligence monitoring across social, print, audio, video, and online sources, used to track and manage brand reputation during active consumer boycotts and PR crises.', 'https://www.meltwater.com/en/blog/crisis-monitoring', 'Incident Handler', 'enabler', NULL, '{}', 67, 'INFERRED', 'partial', 'During the active Starbucks Korea boycott, Meltwater provides 24/7 real-time monitoring of brand mentions across social media, Korean news sources, and global media, tracking sentiment trajectory to assess whether the coordinated multi-channel apology (MC-REP-006) is changing consumer and government sentiment. Red-flag alerts notify the crisis response team of any new escalation — such as presidential statements or new opposition party condemnations — so the team can respond in real time rather than discovering developments through manual monitoring.', 'Meltwater does not provide crisis communications advisory, apology strategy, or direct stakeholder engagement; it provides monitoring data that enables the crisis team to act, but the communications response itself must be led by the client or a PR advisory firm.', 'Meltwater''s verified capabilities align well with the post-incident crisis monitoring role — including boycott tracking, real-time multi-channel sentiment, and red-flag alerting — but evidence rests on product-page marketing claims rather than named case studies, and selection carries a moderate reputation-halo risk given Meltwater''s market prominence relative to smaller specialist alternatives.');
INSERT INTO evidence (id, vendor_id, incident_id, addresses_control, verified_claim, source_span, source_url) VALUES
  (1, 1, 1, 'MC-TEC-003', 'Datadog External Provider Status provides real-time visibility into the health of more than 40 third-party providers, detects degradations faster than vendor status pages, and uses aggregated APM telemetry data to flag provider outages ahead of official confirmation.', 'Datadog External Provider Status provides real-time visibility into the health of more than 40 third-party providers, including 13 AWS services across global regions and widely used SaaS APIs such as GitHub, Stripe, and OpenAI.', 'https://www.datadoghq.com/blog/external-provider-status/'),
  (2, 1, 1, 'MC-TEC-003', 'Datadog External Provider Status detects provider outages before they are confirmed by vendors, as demonstrated by flagging a DynamoDB degradation 32 minutes before AWS acknowledged it on their status page.', 'Datadog automatically monitors APM telemetry data across thousands of customers for errors tied to external providers. By aggregating traffic across organizations,', 'https://www.datadoghq.com/blog/external-provider-status/'),
  (3, 1, 1, 'MC-TEC-003', 'Datadog External Provider Status allows teams to configure monitors to alert when provider degradations are detected, with options to alert for all detected provider issues or only when degradations directly affect specific services, integrating with Slack, PagerDuty, and Microsoft Teams.', 'You can configure monitors to alert your teams when provider degradations are detected. Options include: Alerts for all detected provider issues; Alerts only when degradations directly affect your services.', 'https://www.datadoghq.com/blog/external-provider-status/'),
  (4, 2, 1, 'MC-TEC-001', 'IBM NS1 Connect Filter Chain technology uses the power of DNS to automatically reroute traffic between service providers when there is a network service disruption, monitors network status, and switches endpoints as needed.', 'IBM NS1 Connect Filter Chain™ technology uses the power of DNS to automatically reroute traffic between service providers when there is a network service disruption.', 'https://www.ibm.com/new/product-blog/how-to-improve-network-resilience-with-ns1-connect-filter-chains'),
  (5, 2, 1, 'MC-TEC-012', 'IBM NS1 Connect active-passive failover uses an ''Up'' filter driven by NS1 or third-party monitoring data to detect a primary provider outage and automatically route traffic to secondary systems, creating a logic that prioritizes active systems over passive ones.', 'As in the active-active use case, NS1 or third-party data sources monitor the status of your application delivery infrastructure and route traffic to secondary systems in the event of a primary system outage.', 'https://www.ibm.com/new/product-blog/how-to-improve-network-resilience-with-ns1-connect-filter-chains'),
  (6, 2, 1, 'MC-TPR-022', 'IBM NS1 Connect automatically prevents downtime by combining real-time health checks with intelligent traffic steering to keep applications available without manual intervention.', 'Automatically prevent downtime: Combine real-time health checks with intelligent traffic steering to keep applications available without manual intervention.', 'https://www.ibm.com/products/ns1-connect'),
  (7, 3, 1, 'MC-OPS-008', 'Gremlin''s Blackhole attack blocks network traffic by dropping IP packets at the transport layer, and can be configured to target specific hostnames, IP addresses, and external service providers — including pre-defined third-party cloud provider regions.', 'The Blackhole attack works by blocking network traffic from a host or container. It drops Internet Protocol (IP) packets at the transport layer by using traffic policing features built into the Linux Kernel and the Windows Filtering Platform for', 'https://www.gremlin.com/blog/getting-started-with-blackhole-attacks'),
  (8, 3, 1, 'MC-OPS-008', 'Gremlin''s chaos engineering platform can be used to simulate a black swan event such as a third-party provider outage, allowing teams to test their disaster recovery plan and response procedures in a controlled scenario using FireDrills and Scenarios.', 'In the context of disaster recovery, we can use Chaos Engineering to recreate or simulate a black swan event. This gives us the opportunity to test our DRP and our response procedures in a controlled scenario,', 'https://www.gremlin.com/community/tutorials/testing-disaster-recovery-with-chaos-engineering'),
  (9, 3, 1, 'MC-OPS-002', 'Gremlin identifies third-party provider outages as a named black swan event category requiring disaster recovery planning, stating that identifying potential threats includes ''Third-party provider outages (i.e. loss of infrastructure owned by a third-party cloud provider)''.', 'Third-party provider outages (i.e. loss of infrastructure owned by a third-party cloud provider).', 'https://www.gremlin.com/community/tutorials/testing-disaster-recovery-with-chaos-engineering'),
  (10, 4, 1, 'MC-OPS-018', 'Statuspage is a communication tool that helps companies inform their users about outages and scheduled maintenance, with users able to subscribe to updates via email or text messages when an incident occurs.', 'Statuspage is a communication tool that helps you inform your users about outages and scheduled maintenance. Your users can subscribe to updates via email or text messages when you have an incident,', 'https://support.atlassian.com/statuspage/docs/what-is-statuspage/'),
  (11, 4, 1, 'MC-OPS-018', 'Statuspage does not do any direct monitoring of the customer''s own websites or servers, meaning it operates entirely independently of the customer''s infrastructure and remains available even when the customer''s own systems are offline.', 'Statuspage does not do any direct monitoring of your websites or servers, but you can integrate monitoring tools with Statuspage, or use our API to programmatically update your page.', 'https://support.atlassian.com/statuspage/docs/what-is-statuspage/'),
  (12, 4, 1, 'MC-OPS-018', 'Statuspage leverages dependable, redundant systems to make sure audiences get the right message at the right time when a service is down, enabling companies to build customer trust via transparent communication even during downtime.', 'Customers. Employees. End users. All of these groups (and more!) want to be notified when your service is down. Statuspage leverages dependable, redundant systems to make sure your audiences get the right message at the right time, every time.', 'https://www.atlassian.com/software/statuspage/features'),
  (13, 3, 1, 'practice_page', 'Gremlin''s dependency failure test uses a network blackhole chaos experiment to drop all network traffic to a designated dependency, validating that the application starts up normally and is able to serve customer traffic without that dependency.', 'When you do have a dependency that is out of your control, it''s critical to understand how the system reacts when it is unavailable.', 'https://www.gremlin.com/community/tutorials/4-chaos-experiments-to-start-with'),
  (14, 5, 2, 'MC-PPL-008', 'SafetyCulture''s OSHA Scaffold Inspection Checklist is designed to inspect scaffolds and scaffold parts before each work shift, and after any event that may have caused damage.', 'Use this OSHA Scaffold Inspection Checklist to inspect scaffolds and scaffold parts before each work shift, and after any event that may have caused damage.', 'https://safetyculture.com/library/construction/osha-scaffold-inspection-checklist'),
  (15, 5, 2, 'MC-PHY-009', 'SafetyCulture''s scaffold checklist verifies guardrails and mid-rails and ensures falling object protection, and captures findings, photos, and signatures to generate a compliant report while on-site.', 'confirm guardrails and mid-rails, and ensure falling object protection. Check tie-ins, braces, and guying per manufacturer guidance. Capture findings, photos, and signatures to generate a compliant report with SafetyCulture.', 'https://safetyculture.com/library/construction/osha-scaffold-inspection-checklist-4hsdgn0xeffzo6db'),
  (16, 5, 2, 'MC-PPL-008', 'SafetyCulture documents that OSHA requires a visual inspection to be conducted by a competent person before the start of every shift and after conducting work, and provides scaffold checklists to support this requirement.', 'It is required that a visual inspection be conducted by a competent person before the start of every shift and after conducting work.', 'https://safetyculture.com/topics/scaffolding-safety/10-osha-scaffolding-requirements'),
  (17, 5, 2, 'MC-PPL-008', 'SafetyCulture provides training modules covering fall protection requirements under OSHA 29 CFR 1926.451(g), including guardrail installation, personal fall arrest systems (PFAS), and proper use of PPE.', 'Falls consistently rank as a leading cause of workplace fatalities. As such, courses involving fall protection ( OSHA #3115 ) are non-negotiable in construction scaffold safety training.', 'https://safetyculture.com/topics/scaffolding-safety/scaffolding-safety-training'),
  (18, 6, 2, 'MC-PPL-019', 'Cority contractor management software manages qualifications, permits, training, and performance in one system, automating pre-qualification to ensure contractors are qualified and covered to perform work on site.', 'Manage qualifications, permits, training, and performance in one system.', 'https://www.cority.com/safety-cloud/contractor-management-software/'),
  (19, 6, 2, 'MC-PPL-020', 'Cority automates pre-qualification to ensure contractors are qualified and covered to perform work on site, giving 360-degree visibility into contractor risk to identify hazards early and reduce exposure.', 'Automate prequalification to ensure contractors are qualified, and covered to perform work on site. Gain 360° visibility into contractor risk to identify hazards early and reduce exposure.', 'https://www.cority.com/safety-cloud/contractor-management-software/'),
  (20, 6, 2, 'MC-TPR-021', 'Cority''s SIF Prevention feature identifies high-risk contractors and prioritizes safety interventions, and its AI-powered insights flag contractor risk patterns and concerns early.', 'Identify high-risk contractors and prioritize safety interventions. Embedded AI surfaces contractor risk patterns and flags concerns early.', 'https://www.cority.com/safety-cloud/contractor-management-software/'),
  (21, 6, 2, 'MC-PPL-019', 'Cority''s construction EHS software ensures only trained, qualified and competent contractors and subcontractors can access and work on construction projects.', 'Ensuring only trained, qualified and competent contractors and subcontractors can access and work on construction projects.', 'https://www.cority.com/industries/construction-ehs-software/'),
  (22, 7, 2, 'MC-PPL-020', 'ISNetworld streamlines the prequalification process and ongoing monitoring by enabling contractors to submit health, safety, sustainability, and procurement information for multiple Hiring Clients within one subscription.', 'Contractor Prequalification & Ongoing Monitoring. Streamline the prequalification process and ongoing monitoring by enabling contractors to submit health, safety, sustainability,', 'https://www.isnetworld.com/en'),
  (23, 7, 2, 'MC-PPL-020', 'ISNetworld requires contractors to develop, implement and maintain written health and safety programs and document past and present injury statistics, giving hiring clients a clear picture of contractors'' safe work practices including OSHA logs.', 'Contractors are required to develop, implement and maintain written health and safety programs as well as document past and present injury statistics.', 'https://www.isnetworld.com/en/blog/what-is-contractor-management'),
  (24, 8, 2, 'practice_page', 'Fisher Phillips'' team gets involved at the most critical stage: conducting investigations immediately after an accident has occurred, because when an OSHA inspector arrives, prior probes can open the door to additional claims such as workers compensation or wrongful death.', 'Our team gets involved at the most critical stage: conducting investigations immediately after an accident has occurred. That''s important because when an OSHA inspector arrives, anything prior probes uncover can open the door to additional claims,', 'https://www.fisherphillips.com/en/capabilities/services/workplace-safety-and-catastrophe-management'),
  (25, 8, 2, 'practice_page', 'Fisher Phillips has broad experience in handling cases involving repeat or willful citations, corporate-wide investigations, catastrophic and high visibility cases such as explosions, crane collapses, and employee fatalities.', 'We have broad experience in handling cases involving repeat or willful citations, corporate-wide investigations, whistleblower actions, construction and multi-employer settings, OSHA and MSHA Significant Cases,', 'https://www.fisherphillips.com/en/capabilities/services/workplace-safety-and-catastrophe-management'),
  (26, 8, 2, 'practice_page', 'Fisher Phillips'' catastrophe management service can work with clients to handle related media relations, deal with the families of the deceased or injured employees, prepare for possible civil or criminal proceedings, and work with insurers, regulators, experts and other involved parties.', 'Our team can work with you to develop a strategic plan to address the resulting sophisticated legal issues, handle related media relations, deal with the families of the deceased or injured employees,', 'https://www.fisherphillips.com/en/capabilities/services/workplace-safety-and-catastrophe-management'),
  (27, 8, 2, 'practice_page', 'Fisher Phillips'' safety consulting team can conduct safety audits of facilities for compliance with OSHA regulatory standards, identifying deficiencies, hazards, and areas of non-compliance and providing recommended corrective actions.', 'The consulting team can also conduct safety audits of facilities for compliance with regulatory standards under OSHA, the National Electrical Code (NEC), the National Fire Protection Association (NFPA), and the Americans with Disabilities Act (ADA).', 'https://www.fisherphillips.com/en/capabilities/services/workplace-safety-and-catastrophe-management'),
  (28, 9, 2, 'practice_page', 'When a serious workplace accident occurs, Ogletree Deakins can respond quickly to direct or help conduct an investigation, identify immediate, contributory, and root causes of the accident, and provide recommendations to prevent a recurrence, including taking steps to ensure clients have access to legal privileges that can protect against undesired disclosure.', 'When a serious workplace accident occurs, one or more of our experienced OSH lawyers can respond quickly to direct or help conduct an investigation, identify immediate, contributory, and root causes of the accident,', 'https://ogletree.com/practices-industries/workplace-safety-and-health/'),
  (29, 9, 2, 'practice_page', 'Ogletree Deakins represents employers in willful, egregious, and Severe Violator Enforcement Program cases, as well as in the litigation of other significant contested OSHA cases, before the Occupational Safety and Health Review Commission and appellate courts.', 'Our OSH attorneys represent employers across the nation in "willful," "egregious," and Severe Violator Enforcement Program cases, as well as in the litigation of other significant contested OSHA cases, before the U.S.', 'https://ogletree.com/practices-industries/workplace-safety-and-health/'),
  (30, 9, 2, 'practice_page', 'Ogletree Deakins responded to a fatality in Puerto Rico under investigation by PR-OSHA, executed a strategy to communicate the client''s defences early in the inspection process, and PR-OSHA declined to issue citations.', 'We responded to a fatality in Puerto Rico that was under investigation. We executed a strategy to communicate the client''s defenses to Puerto Rico OSHA (PR-OSHA) early in the inspection process, and PR-OSHA declined to issue citations.', 'https://ogletree.com/practices-industries/workplace-safety-and-health/'),
  (31, 9, 2, 'attorney_profile', 'An Ogletree Deakins attorney vacated two fall protection violations against a controlling employer in a construction fatality matter before the Occupational Safety and Health Review Commission.', 'ALJ vacated two fall protection violations against controlling employer in construction fatality matter, as well as violation alleging', 'https://ogletree.com/people/michael-rubin/'),
  (32, 10, 3, 'MC-OPS-005', 'SafetyChain standardises and enforces Pre-Op inspections, GMPs, sanitation checks, and facility audits so deviations trigger corrective actions, verification steps, and documented closure, ensuring problems are resolved, not repeated.', 'Standardize and enforce Pre-Op inspections, GMPs, sanitation checks, and facility audits so deviations trigger corrective actions, verification steps, and documented closure—ensuring problems are resolved, not repeated.', 'https://safetychain.com/platform/food-safety-programs'),
  (33, 10, 3, 'MC-OPS-005', 'SafetyChain executes HACCP monitoring and required verification workflows with built-in accountability, so missed critical limits drive immediate corrective action, verification, and traceable documentation, supporting defensible HACCP programmes.', 'Execute HACCP monitoring and required verification workflows with built-in accountability, so missed critical limits drive immediate corrective action, verification, and traceable documentation—supporting defensible HACCP programs.', 'https://safetychain.com/platform/food-safety-programs'),
  (34, 10, 3, 'MC-OPS-025', 'SafetyChain CAPA Management helps food and beverage plants resolve issues faster with built-in accountability, clear documentation, and zero paper chasing, with CAPA processes covering deviations, audit findings, and documentation gaps.', 'SafetyChain CAPA Management helps food and beverage plants resolve issues faster with built-in accountability, clear documentation, and zero paper chasing.', 'https://safetychain.com/platform/capa-management'),
  (35, 10, 3, 'MC-OPS-025', 'SafetyChain''s CAPA module links corrective actions to pre-op checks, CCP verifications, internal audits, and other records, enabling investigation and response without jumping between systems, and standardised workflows help teams investigate root causes and complete preventive steps so problems don''t resurface.', 'Standardized workflows help teams investigate root causes and complete preventive steps, so problems don''t resurface.', 'https://safetychain.com/platform/capa-management'),
  (36, 11, 3, 'MC-OPS-005', 'The Neogen analytics EMP, powered by Corvium, enables remote monitoring of multiple processing plant sites, centralises environmental testing data, automates reporting for compliance and conformance, and improves food safety and quality for food companies and consumers.', 'The Neogen analytics EMP, powered by Corvium, enables remote monitoring of multiple processing plant sites, centralizes environmental testing data, automates reporting for compliance and conformance,', 'https://www.dairyfoods.com/articles/94959-neogen-makes-its-environmental-monitoring-program-available-at-no-cost'),
  (37, 11, 3, 'MC-OPS-005', 'Neogen stated that customer needs during the COVID-19 pandemic, as well as demands for greater transparency in food safety and FDA initiatives, point toward increasing expectations requiring food and beverage companies to implement data-driven environmental monitoring programmes.', 'COVID-19 has accelerated the food industry''s movement toward its goal of automating and centralizing data collection for immediate visibility and response', 'https://www.dairyfoods.com/articles/94959-neogen-makes-its-environmental-monitoring-program-available-at-no-cost'),
  (38, 12, 3, 'MC-OPS-029', 'ReposiTrak''s Recall Management solution provides real visibility to inventory levels and locations from distribution centres to stores, with product automatically tracked at the lot level, allowing rapid trace-back of a product through a simple search, along with recall status indications and notifications.', 'Product is automatically tracked at the lot-level, which allows the rapid trace-back of a product through a simple search.', 'https://repositrak.com/press-release/finally-a-faster-and-more-precise-recall-solution-for-the-food-supply-chain-industry/'),
  (39, 12, 3, 'MC-OPS-029', 'ReposiTrak''s Recall Management solution provides real visibility to inventory levels and locations from distribution centres to stores, maintaining virtual inventories and tracking inventories, returns, shrink and more to provide a more accurate view of the location and status of the product being recalled.', 'it is capable of maintaining virtual inventories as well as tracking inventories, returns, shrink and more to provide a more accurate view of the location and status of the product that is being recalled.', 'https://repositrak.com/press-release/finally-a-faster-and-more-precise-recall-solution-for-the-food-supply-chain-industry/'),
  (40, 12, 3, 'MC-OPS-030', 'ReposiTrak''s Traceability Network enables food suppliers to share Traceability Lot Codes and Key Data Elements with downstream customers, enabling rapid identification of affected finished products in the event of a recall.', 'Traceability enables faster, more efficient recalls. Some major retailers have already made the decision to trace entire categories or all foods they sell.', 'https://repositrak.com/traceability-resource-center/'),
  (41, 12, 3, 'MC-TPR-021', 'ReposiTrak operates the world''s largest food traceability and regulatory compliance network, with more than 12,000 retail stores, 8,000 suppliers and dozens of distribution centres using the ReposiTrak Traceability Network to exchange traceability data to meet and exceed the FDA''s FSMA 204 food traceability law.', 'More than 12,000 retail stores, 8,000 suppliers and dozens of distribution centers use the ReposiTrak Traceability Network to exchange food traceability data in order to meet and exceed the FDA''s FSMA 204 food traceability law.', 'https://repositrak.com/traceability-resource-center/'),
  (42, 10, 3, 'MC-OPS-014', 'SafetyChain confirms receiving inspections are performed and documented at the point of receipt, automatically escalating material issues so corrective actions and follow-up prevent supplier-related risks from impacting production.', 'Confirm receiving inspections are performed and documented at the point of receipt, automatically escalating material issues so corrective actions and follow-up prevent supplier-related risks from impacting production.', 'https://safetychain.com/platform/food-safety-programs'),
  (43, 13, 3, 'practice_page', 'For over 30 years, Sedgwick has been the trusted partner for food and drink brands responding to critical safety incidents including foodborne pathogens and bacterial contamination, across prepared foods, fresh produce, dietary supplements and infant formula.', 'For over 30 years, Sedgwick has been the trusted partner for food and drink brands responding to critical safety incidents — from foodborne pathogens and bacterial contamination to allergen mislabeling, packaging defects and more.', 'https://www.sedgwick.com/product-recall/industries/food-and-drink/'),
  (44, 13, 3, 'practice_page', 'Sedgwick delivers comprehensive product recall support for the food and drink sector including regulatory compliance, recall communications, public notifications, and retailer coordination, ensuring swift action to safeguard consumers and protect brand integrity.', 'From regulatory compliance and recall communications to public notifications and retailer coordination, our expertise ensures swift action to safeguard consumers and protect brand integrity.', 'https://www.sedgwick.com/product-recall/industries/food-and-drink/'),
  (45, 13, 3, 'practice_page', 'Sedgwick is trusted by 8 out of 10 of the world''s leading food and drink companies and has executed 7,000+ product recall and incident response programmes in 150+ countries.', 'Trusted by 8/10 of the world''s leading food and drink companies, we offer unparalleled reach, deep industry expertise and proven recall and incident response strategies.', 'https://www.sedgwick.com/product-recall/industries/food-and-drink/'),
  (46, 13, 3, 'practice_page', 'Sedgwick provides consignee identification and management services using data-driven strategies, real-time reporting and actionable insights to ensure only impacted customers are identified and communicated with during a recall.', 'Accurate customer identification, timely notification and effective tracking are essential for successful recall remediation.', 'https://www.sedgwick.com/product-recall/solutions/'),
  (47, 13, 3, 'practice_page', 'Sedgwick''s proprietary data management system provides real-time tracking, visibility, and reporting at every stage of the recall lifecycle, with a centralised platform ensuring precise documentation to help manufacturers meet regulatory requirements.', 'Our proprietary data management system provides real-time tracking, visibility, and reporting at every stage of the recall lifecycle.', 'https://www.sedgwick.com/product-recall/solutions/'),
  (48, 14, 3, 'practice_page', 'Deloitte''s Product Traceability and Transparency Services are designed to facilitate compliance with the FSMA Section 204 Food Traceability Rule and improve value chain transparency, addressing gaps in existing processes, systems, and data that result in delays in product disclosures during recall events.', 'The Deloitte Product Traceability and Transparency Services provide a flexible platform for growth and are designed to facilitate compliance with the US Food Safety Modernization Act section 204 (FSMA 204),', 'https://www.deloitte.com/us/en/industries/consumer/about/deloitte-food-and-product-safety-services.html'),
  (49, 14, 3, 'practice_page', 'Deloitte''s food traceability services establish physical-to-digital links to assist with compliance with the FDA Food Traceability Rule, focusing on establishing readiness around data, process, and stakeholder management through data standardisation, transactional integrity, and technology-enablement.', 'Our food traceability services establish physical-to-digital links to assist with compliance with the FDA Food Traceability Rule, which includes stringent requirements for recordkeeping, documentation, and traceability throughout the supply chain.', 'https://www.deloitte.com/us/en/industries/consumer/about/deloitte-food-and-product-safety-services.html'),
  (50, 14, 3, 'practice_page', 'Deloitte''s Product Lifecycle Management service addresses the significant impact of a recall including the direct costs of customer notification, inventory write-off, and legal costs, and accelerates digital product lifecycle management transformations using a pre-configured out-of-the-box software tool.', 'The impact of a recall is significant and far-reaching, ranging from the direct costs of customer notification, inventory write-off, and legal costs to the indirect costs of incurring brand damage and loss of company goodwill.', 'https://www.deloitte.com/us/en/industries/consumer/about/deloitte-food-and-product-safety-services.html'),
  (51, 15, 4, 'MC-CYB-038', 'When CrowdStrike detects an attack via behavioral IOA, it automatically removes artifacts dropped by the malicious process, kills associated processes, and reverses registry modifications — all automatically without analyst intervention.', 'When CrowdStrike detects an attack, it''ll safely remove supporting artifacts once malicious behavior is identified through an Indicator of Attack.', 'https://www.crowdstrike.com/tech-hub/endpoint-security/crowdstrikes-automated-remeditaion/'),
  (52, 15, 4, 'MC-CYB-038', 'CrowdStrike Falcon''s automated remediation removes files dropped by the malicious process, kills associated processes, and details all quarantined files, killed processes, and deleted registry values in the Falcon console timeline.', 'It''ll also automatically kill associated processes and reverse registry modifications. This all happens automatically and saves the time an analyst would need to manually remove these artifacts.', 'https://www.crowdstrike.com/tech-hub/endpoint-security/crowdstrikes-automated-remeditaion/'),
  (53, 15, 4, 'MC-CYB-038', 'CrowdStrike Falcon detects and prevents macOS SHAMOS malware that configures a Plist file for persistence and saves it to the User''s LaunchDaemons directory, using machine learning and behavioral IOAs at the initial stages of the attack chain.', 'the CrowdStrike Falcon® sensor''s machine learning capabilities and behavior-based detection capabilities (IOAs) can automatically detect and prevent SHAMOS in the initial stages of the attack chain (i.e.,', 'https://www.crowdstrike.com/en-us/blog/falcon-prevents-cookie-spider-shamos-delivery-macos/'),
  (54, 15, 4, 'MC-OPS-009', 'CrowdStrike EDR can isolate the endpoint via network containment, taking swift and instantaneous action by isolating potentially compromised hosts from all network activity, and the containment persists even if the cloud connection is severed and during reboots.', 'CrowdStrike EDR can isolate the endpoint, which is called "network containment." It allows organizations to take swift and instantaneous action by isolating potentially compromised hosts from all network activity.', 'https://www.crowdstrike.com/en-us/cybersecurity-101/endpoint-security/endpoint-detection-and-response-edr/'),
  (55, 16, 4, 'MC-TPR-005', 'Socket for GitHub watches for changes to package manifest files and whenever a new dependency is added in a pull request, Socket analyzes the package''s behavior and leaves a comment if it is a security risk, alerting developers when packages introduce install scripts, obfuscated code, or usage of privileged APIs such as shell, network, filesystem, and environment variables.', 'Socket alerts developers when packages change in security-relevant ways, highlighting events such as the introduction of install scripts, obfuscated code, or usage of privileged APIs such as shell, network, filesystem, and environment variables.', 'https://docs.socket.dev/docs/socket-for-github'),
  (56, 16, 4, 'MC-TPR-005', 'Socket can detect packages that contain known malware by detecting when a bad package version is installed and reporting it to the developer directly in a GitHub pull request.', 'Socket can now protect users from known malware by detecting when a bad package version is installed and reporting it to the developer directly in a GitHub pull request.', 'https://docs.socket.dev/docs/socket-for-github'),
  (57, 16, 4, 'MC-TPR-021', 'Socket''s automated threat detection flagged malicious releases of npm packages including got-fetch after a maintainer account was compromised, detecting suspicious behavior before widespread installation.', 'Socket''s automated threat detection also flagged malicious releases of got-fetch, a package with 20K+ weekly downloads, after an npm maintainer''s account was compromised.', 'https://socket.dev/blog/npm-is-package-hijacked-in-expanding-supply-chain-attack'),
  (58, 17, 4, 'MC-TPR-009', 'Chainguard Libraries eliminates 98%+ of npm supply chain malware risk by building every package from its public, verifiable source code in a SLSA L3-compliant system, preventing build-time and distribution-stage malware injections.', 'Chainguard Libraries eliminates 98%+ of this risk by building every package from its public, verifiable source code in a SLSA L3-compliant system, preventing build-time and distribution-stage malware injections.', 'https://www.chainguard.dev/libraries'),
  (59, 17, 4, 'MC-TPR-009', 'Every Chainguard Library version comes with full provenance and signed SBOMs, so consumers have indisputable proof that dependencies came from the SLSA L3-compliant Chainguard Factory, not from a vulnerable maintainer account.', 'Every version comes built with full provenance and signed SBOMs, so you have indisputable proof that your dependencies came from the SLSA L3-compliant Chainguard Factory, not a machine from a vulnerable maintainer account.', 'https://www.chainguard.dev/libraries'),
  (60, 17, 4, 'MC-TPR-009', 'Chainguard Libraries avoids malicious threats from npm such as the Shai-Hulud worm with 17K+ built-from-source JavaScript projects that are immune from supply chain attacks at the distribution stage.', 'Avoid malicious threats from npm such as the Shai-Hulud worm, is, chalk, and lottie-player with 17K+ built-from-source projects that are ready for your next web app.', 'https://www.chainguard.dev/libraries'),
  (61, 18, 4, 'practice_page', 'Mandiant Incident Response activates on-call incident responders to immediately begin triage activities, minimises business impact through methodical investigation and containment, and achieves rapid recovery of business operations with full breach remediation.', 'On-call incident responders to immediately begin triage activities. Minimize business impact through methodical investigation and containment. Rapid recovery of business operations with full breach remediation.', 'https://www.mandiant.com/services/incident-response'),
  (62, 18, 4, 'practice_page', 'The Mandiant Retainer provides a two-hour response time in the event of a breach, pre-negotiated terms and pre-paid funds for incident response, and flexible access to Mandiant''s world-renowned incident responders, threat intelligence analysts, and security consultants.', 'Two-hour response time in the event of a breach. Pre-negotiated terms and pre-paid funds for proactive services, training, and incident response.', 'https://www.mandiant.com/services/incident-response'),
  (63, 18, 4, 'practice_page', 'Mandiant''s cyber crisis communications planning and response service builds an effective incident communications approach that aligns crisis communications with technical response activities and develops communication playbooks for incidents including disclosure requirements.', 'Align crisis communications with technical response activities. Develop communication playbooks for incidents including disclosure requirements. Evaluate communication processes, tools, and staff in advance of a breach.', 'https://www.mandiant.com/services/incident-response'),
  (64, 19, 4, 'threat_research', 'Unit 42 has published comprehensive threat intelligence on TeamPCP''s multi-stage supply chain attack operations, including documented Cortex XDR XQL hunting queries targeting TeamPCP process execution artifacts, file creation patterns, and network C2 behaviour.', 'The Unit 42 Incident Response team can also be engaged to help with a compromise or to provide a proactive assessment to lower your risk.', 'https://unit42.paloaltonetworks.com/teampcp-supply-chain-attacks/'),
  (65, 19, 4, 'threat_research', 'Unit 42 provides Cortex XDR and XSIAM detections via Behavioral Threat Protection, Advanced WildFire, and Cortex Analytics to help protect against the initial access, C2, and lateral movement patterns used in TeamPCP supply chain attacks.', 'Cortex XDR and XSIAM provide a multi-layer defense — including Behavioral Threat Protection (BTP), Advanced WildFire and Cortex Analytics — to help protect against the initial access, C2 and potential lateral movement described in this article.', 'https://unit42.paloaltonetworks.com/teampcp-supply-chain-attacks/'),
  (66, 19, 4, 'threat_research', 'Unit 42 identified that TeamPCP''s CI/CD attack injected malicious payloads that stole cloud access tokens, SSH keys, and Kubernetes secrets from CI/CD systems and developer workstations, then self-propagated by backdooring every npm package the victim can publish.', 'A malicious npm package published as @bitwarden/cli version 2026.4.0 was identified as part of a broader supply-chain campaign attributed to TeamPCP. The package impersonates the legitimate Bitwarden command-line interface (CLI) password manager.', 'https://unit42.paloaltonetworks.com/monitoring-npm-supply-chain-attacks/?pdf=download&lg=en&_wpnonce=d4f7055bde'),
  (67, 20, 5, 'MC-DAT-015', 'BigID enables organisations to effortlessly classify and categorise unstructured data including biometric data, combining traditional pattern-matching with advanced ML and NLP-based classification, and supports customising classifiers to find unique types of biometric data.', 'Effortlessly classify and categorize challenging and elusive unstructured data, including biometric data. Combine traditional pattern-matching techniques with advanced,', 'https://bigid.com/blog/biometric-data-security/'),
  (68, 20, 5, 'MC-DAT-015', 'BigID allows organisations to detect and investigate unauthorized access to sensitive biometric data, pinpoint data sources containing biometric data with overly permissive access, and simplify access rights management by natively revoking user and group permissions.', 'Detect and investigate unauthorized access to sensitive, biometric data and pinpoint data sources containing biometric data with overly permissive access. Simplify the access rights management by natively revoking user and group permissions.', 'https://bigid.com/blog/biometric-data-security/'),
  (69, 20, 5, 'MC-DAT-015', 'BigID enables organisations to scan for sensitive unstructured biometric data 95% faster with Hyperscan technology across any data source type, including mainframes, messaging apps, pipelines, big data, NoSQL, Cloud IaaS, SaaS, and PaaS.', 'Scan unstructured data, including biometric data, 95% faster with BigID''s Hyperscan technology. Save time and avoid sensitive data blind spots across the cloud with Cloud Auto-Discovery.', 'https://bigid.com/blog/biometric-data-security/'),
  (70, 20, 5, 'MC-DAT-015', 'BigID leverages pre-built sensitivity classification and security policies that align with HIPAA, NIST, and CISA, enabling effective management and protection of sensitive data including biometric data, with automated remediation actions when biometric data is stored, shared, or accessed.', 'Leverage pre-built sensitivity classification, security, and business policies that align with compliance and frameworks such as NIST, CISA, HIPAA, and PCI, enabling effective management and protection of sensitive data.', 'https://bigid.com/blog/biometric-data-security/'),
  (71, 20, 5, 'MC-DAT-025', 'BigID identifies data with legal holds to comply with regulatory requirements and marks over-retained data for deletion, directly supporting a biometric data retention and secure-deletion schedule.', 'define how long to keep it, and mark over-retained data for deletion', 'https://bigid.com/blog/healthcare-cybersecurity-best-practices/'),
  (72, 20, 5, 'MC-DAT-015', 'BigID takes an ML-based approach to automatically classify and tag all sensitive, regulated, and high-risk data — by regulation, document type, policy, attributes, person, and more — covering PHI including biometric identifiers as part of its healthcare data security practice.', 'BigID takes an ML-based approach to automatically classify and tag all sensitive, regulated, and high-risk data — by regulation, document type, policy, attributes, person, and more.', 'https://bigid.com/blog/healthcare-cybersecurity-best-practices/'),
  (73, 20, 5, 'MC-DAT-016', 'BigID provides high-level permission analysis around targeted datasets, identifies users with access to large, sensitive datasets for investigation, and remediates overexposed data to reduce risk and protect personal information across enterprise data stores.', 'Get high-level permission analysis around targeted datasets based on category and type, and identify users with access to large, sensitive datasets for further investigation.', 'https://bigid.com/blog/healthcare-cybersecurity-best-practices/'),
  (74, 20, 5, 'MC-DAT-024', 'BigID simplifies incident response by enabling healthcare organisations to quickly and accurately determine whose data was impacted by a data incident — loss, theft, or misuse — and identify which personal and critical data sets were affected.', 'With BigID, users can quickly and accurately understand whose data was impacted by a data incident — loss, theft, or misuse — and identify which personal and critical data sets have been affected.', 'https://bigid.com/blog/healthcare-cybersecurity-best-practices/'),
  (75, 21, 5, 'MC-CYB-028', 'Delinea PAM for Healthcare manages and secures remote access to protected healthcare information and it is essential to monitor and report on every privileged session, including users outside the network and vendors, with a revolving door of contractors expanding the attack surface.', 'PAM manages and secures remote access to protected healthcare information across the extended organization. It is essential to monitor and report on every privileged sessions, including users outside your network and vendors.', 'https://delinea.com/solutions/privileged-access-management-for-healthcare-organizations'),
  (76, 21, 5, 'MC-CYB-015', 'Delinea enforces the principle of least privilege to prevent credential harvesting and lateral movement by a bad actor who exploits entry-level privileges, using a least-standing privilege approach to securing privileged access that enables detection and blocking of further cyberattack attempts.', 'PAM enforces the principle of least privilege to prevent credential harvesting and lateral movement by a bad actor who exploits entry-level privileges.', 'https://delinea.com/solutions/privileged-access-management-for-healthcare-organizations'),
  (77, 21, 5, 'MC-CYB-028', 'Delinea''s built-in MFA checks identities at all major access gates — including login and privilege elevation — so that even if credentials are stolen or shared, unauthorized users cannot leverage them for privileged access entry to healthcare systems.', 'With Multi-Factor Authentication (MFA), you can tie identities directly to privileged account use, so even if credentials are stolen or shared, unauthorized users can''t leverage them for privileged access entry to your healthcare systems.', 'https://delinea.com/solutions/privileged-access-management-for-healthcare-organizations'),
  (78, 21, 5, 'MC-CYB-028', 'A Delinea-commissioned case study identified that a healthcare organisation needed a solution that could automate service account management and provide secure but appropriately limited third-party access to systems.', 'We needed a solution that could automate the management of our service accounts and also provide secure — but appropriately limited — third-party access to systems.', 'https://delinea.com/solutions/privileged-access-management-for-healthcare-organizations'),
  (79, 21, 5, 'MC-CYB-028', 'Delinea Server PAM enables least privilege for servers with just-in-time privilege elevation and supports passwordless login for both humans and machines.', 'Server Pam enables humans and machines to seamlessly authenticate with passwordless login, enforce least privilege with just-in-time privilege elevation', 'https://delinea.com/blog/least-privilege-for-servers'),
  (80, 22, 5, 'MC-CYB-029', 'Exabeam New-Scale Analytics builds behavioral baselines and uses business context to refine risk scores, enabling identification of subtle changes in users, entities, and non-human identities — when risk meets a set threshold, a case opens for investigation.', 'New-Scale Analytics builds behavioral baselines and uses business context to refine risk scores. Your team can identify subtle changes in users, entities, and non-human identities. ABA highlights activity from AI agents.', 'https://www.exabeam.com/capabilities/ueba/'),
  (81, 22, 5, 'MC-CYB-029', 'Exabeam UEBA learns normal behavior for users and entities to detect meaningful changes over time, with automated timelines that organise related detections chronologically to visualise the full scope of a threat.', 'Automated timelines organize related detections chronologically, visualizing the full scope of a threat. Activity is summarized for anomalies and prebuilt playbooks reduce manual routines so your team can respond faster.', 'https://www.exabeam.com/capabilities/ueba/'),
  (82, 22, 5, 'MC-CYB-029', 'Exabeam''s UEBA engine applies risk-based anomaly detection to user and entity activity and can run on top of an existing SIEM to address insider threats, credential theft, and advanced attacks.', 'New-Scale Analytics can run on top of your SIEM to address insider threats, credential theft, and advanced attacks. Its UEBA engine applies risk-based anomaly detection to user and entity activity', 'https://www.exabeam.com/capabilities/ueba/'),
  (83, 23, 5, 'MC-TPR-024', 'SecurityScorecard''s TITAN platform supplements annual audits with 24/7 visibility into score changes and known-exploited vulnerabilities, validates questionnaire responses against observed technical security behaviour, and enables autonomous remediation workflows.', 'Continuous Monitoring: Supplement annual audits with 24/7 visibility into score changes and KEVs', 'https://securityscorecard.com/solutions/use-cases/third-party-risk-management/'),
  (84, 24, 5, 'practice_page', 'Kroll''s identity monitoring services detect more types of identity theft than credit monitoring alone, monitoring PII including Social Security Numbers, Medical ID Numbers, bank account numbers, and email addresses — with licensed private investigators providing restoration assistance if identity theft is confirmed.', 'Kroll''s unique combination of identity monitoring services can detect more types of identity theft than credit monitoring alone, providing practical help to combat identity theft and fraud.', 'https://www.kroll.com/en/services/cyber/notification-monitoring/identity-monitoring'),
  (85, 24, 5, 'practice_page', 'Kroll monitors Medical ID Numbers as part of its identity monitoring platform, specifically because criminals can exploit sensitive data including Medical ID Numbers for months or years before suspicious activity appears in credit reports.', 'When compromised, criminals can take advantage of sensitive data like Social Security Numbers and Medical ID Numbers for months, or even years, before suspicious activity appears in credit reports.', 'https://www.kroll.com/en/services/cyber/notification-monitoring/identity-monitoring'),
  (86, 24, 5, 'practice_page', 'Kroll''s data breach notification team has more than 20 years of experience handling some of the largest and most complex breach notification requirements in the world, including for healthcare and other highly regulated industries.', 'Kroll''s data breach notification team has more than 20 years of breach notification experience, handling some of the largest and most complex requirements in the world.', 'https://www.kroll.com/en/services/cyber/notification-monitoring/breach-notification'),
  (87, 24, 5, 'published_research', 'Kroll found that healthcare was the most breached industry in 2024, accounting for nearly 23% of breaches handled by Kroll, demonstrating its active role as the leading post-breach response provider for the healthcare sector.', 'In 2024, healthcare was the most breached industry, accounting for nearly a quarter (23%) of breaches handled by Kroll, compared to 18% in 2023.', 'https://www.kroll.com/en/publications/cyber/data-breach-outlook-2025'),
  (88, 25, 6, 'MC-TPR-021', 'HighRadius credit scoring AI software continuously monitors payment deterioration, utilization spikes, and adverse financial events — including bankruptcy alerts — in real time, allowing credit teams to adjust limits proactively before losses accumulate.', 'Continuous monitoring identifies deteriorating payment behavior, utilization spikes, and adverse financial events as they occur.', 'https://www.highradius.com/software/order-to-cash/credit-management/credit-scoring-and-risk-assessment-automation/'),
  (89, 25, 6, 'MC-TPR-021', 'HighRadius credit scoring software detects bankruptcy alerts and rating changes as external risk signals that trigger automated score recalculation and recommended credit limit actions.', 'Capture external risk signals: The credit scoring platform detects bankruptcy alerts, rating changes, and M&A events. Trigger automated score recalculation: The credit scoring engine dynamically updates scores and recommended limits.', 'https://www.highradius.com/software/order-to-cash/credit-management/credit-scoring-and-risk-assessment-automation/'),
  (90, 25, 6, 'MC-TPR-023', 'HighRadius assigns customers into risk tiers based on Probability of Default outputs and enforces policy-aligned credit limit thresholds, supporting the recalibration of early-warning score thresholds across a vendor''s counterparty book.', 'Assign risk classes automatically: The credit score software categorizes customers into risk tiers based on PD outputs. Generate optimized credit limits: The credit analysis software links scoring results to limit recommendations.', 'https://www.highradius.com/software/order-to-cash/credit-management/credit-scoring-and-risk-assessment-automation/'),
  (91, 26, 6, 'MC-TPR-021', 'Creditsafe advises that key indicators of potential bankruptcy include an increase in Days Beyond Terms (DBT) and a declining credit score, and that vendors should use credit monitoring tools to avoid being caught in a bankruptcy situation.', 'Key indicators of potential bankruptcy include an increase in Days Beyond Terms (DBT) and a declining credit score. These could signal financial trouble, and you should proactively check in with the company to understand what''s happening.', 'https://www.creditsafe.com/us/en/resources/blog/credit/what-happens-when-a-company-files-for-bankruptcy.html'),
  (92, 26, 6, 'MC-TPR-021', 'Creditsafe company monitoring sends real-time email alerts when a monitored company''s credit report changes, enabling vendors to spot the warning signs and act before it is too late.', 'Company Monitoring helps you to keep a close eye on your customers and suppliers without the need to regularly check their company reports.', 'https://www.creditsafe.com/gb/en/credit-risk/credit-reports/company-credit-reports/company-monitoring.html'),
  (93, 27, 6, 'MC-FIN-029', 'Allianz Trade Corporate Advantage is an insurance policy that covers trade credit receivables against the customer''s failure to pay their trade debts due to insolvency or because they failed to pay within the agreed timeframe.', 'Corporate Advantage is an insurance policy that covers trade credit receivables in both domestic and export markets. It is protection against your customers'' failure to pay their trade debts due to insolvency or because they failed to pay within the', 'https://www.allianz-trade.com/en_US/what-is-trade-credit-insurance/our-solutions/corporate-advantage.html'),
  (94, 27, 6, 'MC-FIN-030', 'Allianz Trade''s ongoing customer analysis gathers and analyzes information about insured buyers from multiple sources and alerts the policyholder if anything happens that impacts the customer''s insurability.', 'our risk experts gather and analyze information about your customers from a variety of sources, including visits to the customer, credit reporting agencies, public records, receipt of financial statements, and past-due reports.', 'https://www.allianz-trade.com/en_US/what-is-trade-credit-insurance/our-solutions/corporate-advantage.html'),
  (95, 28, 6, 'practice_page', 'Kelley Drye''s creditor-oriented practice is involved in virtually every major retail bankruptcy case and its award-winning bankruptcy representations have been recognized by multiple professional associations.', 'Kelley Drye''s creditor-oriented practice is involved in virtually every major retail bankruptcy case, and our award-winning bankruptcy representations have been recognized by the Turnaround Management Association,', 'https://www.kelleydrye.com/news/kelley-drye-represents-general-growth-properties-in-unique-aeropostale-acquisition'),
  (96, 28, 6, 'practice_page', 'Kelley Drye has represented more than 75 creditors'' committees in industries including apparel and routinely advises vendors on pursuing 503(b)(9) claims and preference and fraudulent conveyance litigation defence.', 'Over the past decade, the bankruptcy team has represented more than 75 creditors'' committees spanning various industries including apparel, automotive, beauty & cosmetics, digital media, distribution, financial services, furniture, health & fitness,', 'https://www.kelleydrye.com/practices/bankruptcy-and-restructuring'),
  (97, 28, 6, 'practice_page', 'Kelley Drye''s fashion and retail practice has confronted virtually every bankruptcy issue that may arise in a retail bankruptcy case and has established relationships with retail liquidators, consultants, lenders, and most retail debtors'' counsel across the country.', 'The firm has confronted virtually every bankruptcy and real estate issue that may arise in a retail bankruptcy case. We have established relationships with retail liquidators, retail consultants,', 'https://www.kelleydrye.com/industries/fashion-and-retail'),
  (98, 29, 6, 'practice_page', 'FTI Consulting is the market leader in retail restructuring and represents companies, private equity firms, secured and unsecured creditors, and other stakeholders in both in-court and out-of-court restructurings and turnarounds.', 'FTI Consulting is the market leader in retail restructuring and has advised many high-profile retailing clients facing complex situations.', 'https://www.fticonsulting.com/industries/retail-and-consumer-products/retail-turnaround-restructuring'),
  (99, 30, 7, 'MC-REG-020', 'Fangda has extensive experience in handling administrative investigations conducted by the CSRC and criminal investigations involving potential securities rule violations, as well as negotiating for settlement with the CSRC.', 'We have extensive experience in handling administrative investigations conducted by the CSRC and criminal investigations involving potential securities rule violations, as well as negotiating for settlement with the CSRC.', 'https://www.fangdalaw.com/en/bussiness/index14.html'),
