SET client_encoding = 'UTF8';

DROP TABLE IF EXISTS evidence, products, vendors, incidents, vendor_onboarding CASCADE;

CREATE TABLE incidents (
  id            SERIAL PRIMARY KEY,
  name          TEXT NOT NULL,
  risk_coverage_vendors    INT,
  incident_handler_vendors INT,
  total_vendors INT
);
CREATE TABLE vendors (
  id          SERIAL PRIMARY KEY,
  name        TEXT NOT NULL,
  entity_type TEXT,
  hq          TEXT,
  domain      TEXT,
  website     TEXT,
  logo_url    TEXT
);
CREATE TABLE products (
  id               SERIAL PRIMARY KEY,
  vendor_id        INT REFERENCES vendors(id) ON DELETE CASCADE,
  incident_id      INT REFERENCES incidents(id) ON DELETE SET NULL,
  name             TEXT NOT NULL,
  what_they_do     TEXT,
  product_url      TEXT,
  vendor_group     TEXT,
  role             TEXT,
  primary_mc       TEXT,
  covers_controls  TEXT[] DEFAULT '{}',
  ai_verdict       INT,
  confidence       TEXT,
  fit              TEXT,
  how_it_mitigates TEXT,
  known_limits     TEXT,
  score_rationale  TEXT,
  listing_type     TEXT NOT NULL DEFAULT 'product'  -- product | service | hybrid
);
CREATE TABLE evidence (
  id                SERIAL PRIMARY KEY,
  vendor_id         INT REFERENCES vendors(id) ON DELETE CASCADE,
  incident_id       INT REFERENCES incidents(id) ON DELETE SET NULL,
  addresses_control TEXT,
  verified_claim    TEXT,
  source_span       TEXT,
  source_url        TEXT
);
CREATE TABLE vendor_onboarding (
  id                  SERIAL PRIMARY KEY,
  work_email          TEXT UNIQUE NOT NULL,
  company_name        TEXT,
  website             TEXT,
  hq                  TEXT,
  founded             TEXT,
  company_size        TEXT,
  certifications      TEXT,
  product_name        TEXT,
  product_description TEXT,
  product_shape       TEXT,
  video_state         TEXT DEFAULT 'none',
  video_url           TEXT,
  evidence            JSONB DEFAULT '[]',
  extra_products      JSONB DEFAULT '[]',
  current_step        INT  DEFAULT 0,
  status              TEXT DEFAULT 'draft',
  created_at          TIMESTAMPTZ DEFAULT now(),
  updated_at          TIMESTAMPTZ DEFAULT now()
);

CREATE INDEX idx_products_vendor ON products(vendor_id);
CREATE INDEX idx_products_incident ON products(incident_id);
CREATE INDEX idx_evidence_vendor_incident ON evidence(vendor_id, incident_id);





